def _sha256(path: Path) -> str:
    digest = hashlib.sha256()
    with path.open("rb") as handle:
        for chunk in iter(lambda: handle.read(1024 * 1024), b""):
            digest.update(chunk)
    return digest.hexdigest()


def _font(size: int, bold: bool = False) -> ImageFont.ImageFont:
    candidates = [
        "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf" if bold else "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf",
        "/usr/share/fonts/truetype/liberation2/LiberationSans-Bold.ttf" if bold else "/usr/share/fonts/truetype/liberation2/LiberationSans-Regular.ttf",
    ]
    for candidate in candidates:
        path = Path(candidate)
        if path.exists():
            return ImageFont.truetype(str(path), size=size)
    return ImageFont.load_default()


def _wrap(draw: ImageDraw.ImageDraw, text: str, font: ImageFont.ImageFont, width: int) -> list[str]:
    words = text.split()
    lines: list[str] = []
    current = ""
    for word in words:
        trial = word if not current else f"{current} {word}"
        bbox = draw.textbbox((0, 0), trial, font=font)
        if bbox[2] - bbox[0] <= width or not current:
            current = trial
        else:
            lines.append(current)
            current = word
    if current:
        lines.append(current)
    return lines


def _draw_box(
    draw: ImageDraw.ImageDraw,
    xy: tuple[int, int, int, int],
    title: str,
    body: str,
    fill: tuple[int, int, int],
    outline: tuple[int, int, int],
) -> None:
    draw.rounded_rectangle(xy, radius=18, fill=fill, outline=outline, width=3)
    x0, y0, x1, _ = xy
    title_font = _font(25, bold=True)
    body_font = _font(18)
    draw.text((x0 + 20, y0 + 18), title, fill=(30, 38, 50), font=title_font)
    y = y0 + 58
    for line in _wrap(draw, body, body_font, x1 - x0 - 40):
        draw.text((x0 + 20, y), line, fill=(48, 56, 68), font=body_font)
        y += 25


def _arrow(draw: ImageDraw.ImageDraw, start: tuple[int, int], end: tuple[int, int]) -> None:
    draw.line([start, end], fill=(55, 65, 80), width=4)
    angle = np.arctan2(end[1] - start[1], end[0] - start[0])
    size = 16
    points = [
        end,
        (int(end[0] - size * np.cos(angle - 0.45)), int(end[1] - size * np.sin(angle - 0.45))),
        (int(end[0] - size * np.cos(angle + 0.45)), int(end[1] - size * np.sin(angle + 0.45))),
    ]
    draw.polygon(points, fill=(55, 65, 80))


def _draw_wrapped(
    draw: ImageDraw.ImageDraw,
    xy: tuple[int, int],
    text: str,
    font: ImageFont.ImageFont,
    fill: tuple[int, int, int],
    width: int,
    line_gap: int = 6,
    max_lines: int | None = None,
) -> int:
    x, y = xy
    lines: list[str] = []
    for paragraph in text.replace("\\n", "\n").splitlines():
        wrapped = _wrap(draw, paragraph.strip(), font, width)
        lines.extend(wrapped or [""])
    if max_lines is not None and len(lines) > max_lines:
        lines = lines[:max_lines]
        lines[-1] = lines[-1].rstrip(".,;:") + "..."
    line_h = draw.textbbox((0, 0), "Ag", font=font)[3] + line_gap
    for line in lines:
        draw.text((x, y), line, fill=fill, font=font)
        y += line_h
    return y


def _panel(
    draw: ImageDraw.ImageDraw,
    xy: tuple[int, int, int, int],
    label: str,
    title: str,
    accent: tuple[int, int, int],
    subtitle: str | None = None,
) -> None:
    x0, y0, x1, y1 = xy
    draw.rounded_rectangle((x0 + 7, y0 + 8, x1 + 7, y1 + 8), radius=20, fill=(225, 231, 238))
    draw.rounded_rectangle((x0 + 3, y0 + 4, x1 + 3, y1 + 4), radius=19, fill=(237, 241, 246))
    draw.rounded_rectangle(xy, radius=18, fill=(255, 255, 255), outline=(185, 194, 205), width=2)
    header_fill = _blend(accent, (255, 255, 255), 0.9)
    draw.rounded_rectangle((x0 + 2, y0 + 2, x1 - 2, y0 + 76), radius=16, fill=header_fill, outline=None)
    draw.rounded_rectangle((x0 + 16, y0 + 70, x1 - 16, y0 + 76), radius=3, fill=_blend(accent, (255, 255, 255), 0.28))
    draw.rounded_rectangle((x0, y0, x0 + 58, y0 + 48), radius=12, fill=accent, outline=accent, width=1)
    draw.text((x0 + 17, y0 + 8), label, fill=(255, 255, 255), font=_font(30, bold=True))
    draw.text((x0 + 76, y0 + 10), title, fill=(22, 31, 45), font=_font(31, bold=True))
    if subtitle:
        draw.text((x0 + 76, y0 + 48), subtitle, fill=(88, 98, 112), font=_font(20))
    draw.line((x0 + 26, y0 + 76, x1 - 26, y0 + 76), fill=(225, 230, 236), width=2)


def _badge(
    draw: ImageDraw.ImageDraw,
    xy: tuple[int, int, int, int],
    title: str,
    body: str,
    fill: tuple[int, int, int],
    outline: tuple[int, int, int],
    title_size: int = 22,
    body_size: int = 17,
) -> None:
    x0, y0, x1, y1 = xy
    draw.rounded_rectangle((x0 + 4, y0 + 5, x1 + 4, y1 + 5), radius=14, fill=(232, 237, 243))
    draw.rounded_rectangle(xy, radius=13, fill=fill, outline=outline, width=2)
    title_font = _font(title_size, bold=True)
    title_lines = title.replace("\\n", "\n").splitlines()
    title_line_h = draw.textbbox((0, 0), "Ag", font=title_font)[3] + 3
    for idx, line in enumerate(title_lines):
        draw.text((x0 + 14, y0 + 10 + idx * title_line_h), line, fill=(24, 33, 45), font=title_font)
    body_y = y0 + 10 + max(1, len(title_lines)) * title_line_h + 10
    body_font = _font(body_size)
    line_h = draw.textbbox((0, 0), "Ag", font=body_font)[3] + 4
    max_lines = max(1, (y1 - body_y - 8) // max(line_h, 1))
    _draw_wrapped(draw, (x0 + 14, body_y), body, body_font, (54, 64, 78), x1 - x0 - 28, line_gap=4, max_lines=max_lines)


def _small_node(
    draw: ImageDraw.ImageDraw,
    center: tuple[int, int],
    label: str,
    color: tuple[int, int, int],
    radius: int = 34,
    font_size: int = 17,
) -> None:
    x, y = center
    draw.ellipse((x - radius, y - radius, x + radius, y + radius), fill=color, outline=(80, 89, 102), width=2)
    label_lines = label.split("\\n")
    line_h = 19
    start_y = y - (len(label_lines) * line_h) // 2
    for idx, line in enumerate(label_lines):
        bbox = draw.textbbox((0, 0), line, font=_font(font_size, bold=True))
        draw.text((x - (bbox[2] - bbox[0]) // 2, start_y + idx * line_h), line, fill=(255, 255, 255), font=_font(font_size, bold=True))


def _mini_table(
    draw: ImageDraw.ImageDraw,
    xy: tuple[int, int, int, int],
    headers: list[str],
    rows: list[list[str]],
    col_widths: list[int],
) -> None:
    x0, y0, x1, _ = xy
    row_h = 44
    draw.rounded_rectangle(xy, radius=10, fill=(250, 252, 255), outline=(205, 212, 222), width=2)
    x = x0
    for idx, header in enumerate(headers):
        draw.rectangle((x, y0, min(x + col_widths[idx], x1), y0 + row_h), fill=(235, 241, 248))
        draw.text((x + 10, y0 + 12), header, fill=(35, 45, 60), font=_font(17, bold=True))
        x += col_widths[idx]
    y = y0 + row_h
    for row in rows:
        x = x0
        for idx, value in enumerate(row):
            draw.rectangle((x, y, min(x + col_widths[idx], x1), y + row_h), outline=(224, 229, 235), width=1)
            draw.text((x + 10, y + 12), value, fill=(50, 60, 74), font=_font(16))
            x += col_widths[idx]
        y += row_h


def _load_json(path: str | Path) -> dict[str, Any]:
    path = Path(path)
    if not path.exists():
        return {}
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return {}


def _load_csv(path: str | Path) -> pd.DataFrame:
    path = Path(path)
    if not path.exists():
        return pd.DataFrame()
    try:
        return pd.read_csv(path)
    except Exception:
        return pd.DataFrame()


def _draw_spot_map(draw: ImageDraw.ImageDraw, xy: tuple[int, int, int, int]) -> None:
    x0, y0, x1, y1 = xy
    coords = _load_csv("data/processed/cytassist_xenium_rep2_common297/spot_coords.csv")
    qc = _load_csv("data/processed/xenium_to_visium_benchmark/cytassist_rep2_radius55/spot_ground_truth_qc.csv")
    draw.rounded_rectangle(xy, radius=12, fill=(248, 250, 252), outline=(205, 212, 222), width=2)
    if coords.empty or qc.empty:
        for row in range(18):
            for col in range(24):
                px = x0 + 24 + col * 17 + (row % 2) * 8
                py = y0 + 24 + row * 16
                fill = (49, 126, 168) if (row * col) % 17 == 0 else (180, 188, 198)
                draw.ellipse((px - 4, py - 4, px + 4, py + 4), fill=fill)
        return
    merged = coords.merge(qc[["spot_id", "has_xenium_ground_truth"]], on="spot_id", how="left")
    merged = merged.loc[merged.get("in_tissue", 1).astype(int).eq(1)].copy()
    if len(merged) > 1600:
        merged = merged.sample(1600, random_state=7)
    xs = merged["x"].astype(float).to_numpy()
    ys = merged["y"].astype(float).to_numpy()
    xs = (xs - xs.min()) / max(xs.max() - xs.min(), 1.0)
    ys = (ys - ys.min()) / max(ys.max() - ys.min(), 1.0)
    gt = merged["has_xenium_ground_truth"].astype(str).str.lower().isin({"true", "1", "yes"})
    for px, py, has_gt in zip(xs, ys, gt):
        cx = int(x0 + 22 + px * (x1 - x0 - 44))
        cy = int(y0 + 22 + py * (y1 - y0 - 44))
        color = (45, 126, 168) if bool(has_gt) else (185, 193, 203)
        r = 5 if bool(has_gt) else 3
        draw.ellipse((cx - r, cy - r, cx + r, cy + r), fill=color)
    draw.ellipse((x0 + 28, y1 - 58, x0 + 78, y1 - 8), outline=(211, 121, 47), width=3)
    draw.text((x0 + 88, y1 - 46), "radius 55", fill=(74, 86, 100), font=_font(17, bold=True))


def _draw_mini_bars(draw: ImageDraw.ImageDraw, xy: tuple[int, int, int, int], values: list[float], labels: list[str], colors: list[tuple[int, int, int]]) -> None:
    x0, y0, x1, y1 = xy
    draw.rounded_rectangle((x0 + 4, y0 + 5, x1 + 4, y1 + 5), radius=14, fill=(232, 237, 243))
    draw.rounded_rectangle(xy, radius=12, fill=(250, 252, 255), outline=(205, 212, 222), width=2)
    draw.text((x0 + 20, y0 + 14), "JSD benchmark", fill=(35, 45, 60), font=_font(18, bold=True))
    draw.text((x1 - 132, y0 + 17), "lower is better", fill=(88, 98, 112), font=_font(13, bold=True))
    if not values:
        return
    plot_x0, plot_y0 = x0 + 50, y0 + 58
    plot_x1, plot_y1 = x1 - 34, y1 - 52
    max_val = max(max(values), 1e-6)
    min_val = min(values)
    for frac in np.linspace(0.0, 1.0, 5):
        gy = int(plot_y1 - frac * (plot_y1 - plot_y0))
        draw.line((plot_x0, gy, plot_x1, gy), fill=(226, 232, 239), width=1)
    draw.line((plot_x0, plot_y1, plot_x1, plot_y1), fill=(155, 166, 180), width=2)
    n = len(values)
    step = (plot_x1 - plot_x0) / max(n, 1)
    for idx, value in enumerate(values):
        cx = int(plot_x0 + step * (idx + 0.5))
        norm = value / max_val
        cy = int(plot_y1 - norm * (plot_y1 - plot_y0))
        color = colors[idx] if idx < len(colors) else (157, 168, 180)
        line_col = tuple(int(0.72 * c + 0.28 * 255) for c in color)
        draw.line((cx, plot_y1, cx, cy), fill=line_col, width=5 if idx == 0 else 4)
        r = 16 if idx == 0 else 13
        draw.ellipse((cx - r, cy - r, cx + r, cy + r), fill=color, outline=(255, 255, 255), width=3)
        short = labels[idx].replace("WaveST-Gate", "WaveST").replace("_", " ")[:10]
        bbox = draw.textbbox((0, 0), short, font=_font(12, bold=idx == 0))
        draw.text((cx - (bbox[2] - bbox[0]) // 2, y1 - 36), short, fill=(54, 64, 78), font=_font(12, bold=idx == 0))
        if idx == 0:
            pill = (cx - 46, max(plot_y0 + 4, cy - 44), cx + 46, max(plot_y0 + 28, cy - 18))
            draw.rounded_rectangle(pill, radius=11, fill=(231, 244, 249), outline=color, width=2)
            draw.text((pill[0] + 13, pill[1] + 5), "rank 1", fill=color, font=_font(12, bold=True))
    draw.text((plot_x0, plot_y0 - 4), f"{max_val:.3f}", fill=(112, 122, 136), font=_font(12))
    draw.text((plot_x0, plot_y1 - 15), f"{min_val:.3f}", fill=(112, 122, 136), font=_font(12))


def _blend(c0: tuple[int, int, int], c1: tuple[int, int, int], t: float) -> tuple[int, int, int]:
    t = max(0.0, min(1.0, float(t)))
    return tuple(int(c0[i] * (1 - t) + c1[i] * t) for i in range(3))


def _draw_sensitivity_matrix(
    draw: ImageDraw.ImageDraw,
    xy: tuple[int, int, int, int],
    frame: pd.DataFrame,
    title: str,
    accent: tuple[int, int, int],
) -> None:
    x0, y0, x1, y1 = xy
    draw.rounded_rectangle((x0 + 4, y0 + 5, x1 + 4, y1 + 5), radius=13, fill=(232, 237, 243))
    draw.rounded_rectangle(xy, radius=12, fill=(250, 252, 255), outline=accent, width=2)
    draw.text((x0 + 18, y0 + 12), title, fill=(35, 45, 60), font=_font(17, bold=True))
    if frame.empty or not {"radius", "min_xenium_cells", "jsd"}.issubset(frame.columns):
        _draw_wrapped(draw, (x0 + 18, y0 + 48), "sensitivity table unavailable", _font(14), (88, 98, 112), x1 - x0 - 36, max_lines=2)
        return
    pivot = frame.pivot_table(index="radius", columns="min_xenium_cells", values="jsd", aggfunc="mean").sort_index()
    values = pivot.to_numpy(dtype=float)
    finite = np.isfinite(values)
    lo = float(np.nanmin(values[finite])) if finite.any() else 0.0
    hi = float(np.nanmax(values[finite])) if finite.any() else 1.0
    rows = list(pivot.index)
    cols = list(pivot.columns)
    grid_x0, grid_y0 = x0 + 58, y0 + 56
    grid_x1, grid_y1 = x1 - 22, y1 - 38
    cell_w = max(18, (grid_x1 - grid_x0) // max(len(cols), 1))
    cell_h = max(18, (grid_y1 - grid_y0) // max(len(rows), 1))
    low = (72, 148, 107)
    high = (207, 132, 40)
    for ri, radius in enumerate(rows):
        draw.text((x0 + 18, grid_y0 + ri * cell_h + 7), f"r{int(radius)}", fill=(74, 86, 100), font=_font(12, bold=True))
        for ci, threshold in enumerate(cols):
            value = float(pivot.iloc[ri, ci])
            t = (value - lo) / max(hi - lo, 1e-9)
            color = _blend(low, high, t)
            rx0 = grid_x0 + ci * cell_w
            ry0 = grid_y0 + ri * cell_h
            draw.rounded_rectangle((rx0 + 2, ry0 + 2, rx0 + cell_w - 4, ry0 + cell_h - 4), radius=5, fill=color)
            if ri == 0:
                draw.text((rx0 + 4, y1 - 28), str(int(threshold)), fill=(74, 86, 100), font=_font(10, bold=True))
    if 55.0 in [float(row) for row in rows]:
        ri = [float(row) for row in rows].index(55.0)
        ry = grid_y0 + ri * cell_h
        draw.rounded_rectangle((grid_x0 - 4, ry - 2, grid_x0 + len(cols) * cell_w + 2, ry + cell_h), radius=7, outline=(35, 45, 60), width=3)
        draw.text((x1 - 154, ry + 5), "selected r55", fill=(35, 45, 60), font=_font(11, bold=True))
    draw.text((x0 + 18, y1 - 28), "min cells", fill=(88, 98, 112), font=_font(11, bold=True))
    draw.text((x1 - 132, y0 + 16), "lower JSD", fill=(88, 98, 112), font=_font(12, bold=True))


def _draw_split_sparkline(
    draw: ImageDraw.ImageDraw,
    xy: tuple[int, int, int, int],
    frame: pd.DataFrame,
    accent: tuple[int, int, int],
) -> None:
    x0, y0, x1, y1 = xy
    draw.rounded_rectangle((x0 + 4, y0 + 5, x1 + 4, y1 + 5), radius=13, fill=(232, 237, 243))
    draw.rounded_rectangle(xy, radius=12, fill=(250, 252, 255), outline=accent, width=2)
    draw.text((x0 + 16, y0 + 12), "split sensitivity", fill=(35, 45, 60), font=_font(17, bold=True))
    if frame.empty or not {"split", "mean_jsd", "sd_jsd"}.issubset(frame.columns):
        _draw_wrapped(draw, (x0 + 16, y0 + 46), "split table unavailable", _font(14), (88, 98, 112), x1 - x0 - 32, max_lines=2)
        return
    data = frame.sort_values("split").copy()
    values = data["mean_jsd"].astype(float).to_numpy()
    errors = data["sd_jsd"].astype(float).to_numpy()
    lo = float(np.nanmin(values - errors))
    hi = float(np.nanmax(values + errors))
    px0, py0, px1, py1 = x0 + 44, y0 + 48, x1 - 28, y1 - 34
    draw.line((px0, py1, px1, py1), fill=(176, 186, 198), width=2)
    points: list[tuple[int, int]] = []
    for idx, (_, row) in enumerate(data.iterrows()):
        cx = int(px0 + (idx + 0.5) * (px1 - px0) / max(len(data), 1))
        mean = float(row["mean_jsd"])
        sd = float(row["sd_jsd"])
        cy = int(py1 - (mean - lo) / max(hi - lo, 1e-9) * (py1 - py0))
        ey0 = int(py1 - (mean + sd - lo) / max(hi - lo, 1e-9) * (py1 - py0))
        ey1 = int(py1 - (mean - sd - lo) / max(hi - lo, 1e-9) * (py1 - py0))
        draw.line((cx, ey0, cx, ey1), fill=_blend(accent, (255, 255, 255), 0.35), width=4)
        draw.ellipse((cx - 11, cy - 11, cx + 11, cy + 11), fill=accent, outline=(255, 255, 255), width=3)
        draw.text((cx - 18, y1 - 27), str(row["split"])[:5], fill=(74, 86, 100), font=_font(11, bold=True))
        points.append((cx, cy))
    if len(points) > 1:
        draw.line(points, fill=accent, width=3)


def _draw_calibration_curve(
    draw: ImageDraw.ImageDraw,
    xy: tuple[int, int, int, int],
    frame: pd.DataFrame,
    accent: tuple[int, int, int],
) -> None:
    x0, y0, x1, y1 = xy
    draw.rounded_rectangle((x0 + 4, y0 + 5, x1 + 4, y1 + 5), radius=13, fill=(232, 237, 243))
    draw.rounded_rectangle(xy, radius=12, fill=(250, 252, 255), outline=accent, width=2)
    draw.text((x0 + 16, y0 + 12), "uncertainty calibration", fill=(35, 45, 60), font=_font(17, bold=True))
    if frame.empty or not {"mean_uncertainty", "mean_jsd"}.issubset(frame.columns):
        _draw_wrapped(draw, (x0 + 16, y0 + 46), "calibration table unavailable", _font(14), (88, 98, 112), x1 - x0 - 32, max_lines=2)
        return
    data = frame.sort_values("mean_uncertainty")
    xs = data["mean_uncertainty"].astype(float).to_numpy()
    ys = data["mean_jsd"].astype(float).to_numpy()
    px0, py0, px1, py1 = x0 + 42, y0 + 50, x1 - 28, y1 - 32
    draw.line((px0, py1, px1, py1), fill=(176, 186, 198), width=2)
    draw.line((px0, py0, px0, py1), fill=(176, 186, 198), width=2)
    xlo, xhi = float(xs.min()), float(xs.max())
    ylo, yhi = float(ys.min()), float(ys.max())
    pts = []
    for xval, yval in zip(xs, ys):
        px = int(px0 + (xval - xlo) / max(xhi - xlo, 1e-9) * (px1 - px0))
        py = int(py1 - (yval - ylo) / max(yhi - ylo, 1e-9) * (py1 - py0))
        pts.append((px, py))
    if len(pts) > 1:
        draw.line(pts, fill=accent, width=4)
    for idx, pt in enumerate(pts):
        if idx % 2 == 0 or idx == len(pts) - 1:
            draw.ellipse((pt[0] - 6, pt[1] - 6, pt[0] + 6, pt[1] + 6), fill=accent, outline=(255, 255, 255), width=2)
    draw.text((px0, y1 - 24), "risk", fill=(88, 98, 112), font=_font(11, bold=True))
    draw.text((x1 - 72, y1 - 24), "error", fill=(88, 98, 112), font=_font(11, bold=True))


def _draw_audit_badges(
    draw: ImageDraw.ImageDraw,
    xy: tuple[int, int, int, int],
    audit: dict[str, Any],
    accent: tuple[int, int, int],
) -> None:
    x0, y0, x1, y1 = xy
    draw.rounded_rectangle((x0 + 4, y0 + 5, x1 + 4, y1 + 5), radius=13, fill=(232, 237, 243))
    draw.rounded_rectangle(xy, radius=12, fill=(250, 252, 255), outline=accent, width=2)
    draw.text((x0 + 16, y0 + 12), "reviewer controls", fill=(35, 45, 60), font=_font(17, bold=True))
    status = str(audit.get("overall_status", "audit"))
    split = audit.get("split_audit", {}) if isinstance(audit, dict) else {}
    overlaps = split.get("split_overlaps", {}) if isinstance(split, dict) else {}
    overlap_ok = all(int(v) == 0 for v in overlaps.values()) if overlaps else True
    labels = [
        ("split", "0 overlap" if overlap_ok else "check", (72, 148, 107)),
        ("perm", "label ctrl", (207, 132, 40)),
        ("fair", "13 baselines", (58, 121, 176)),
        ("release", "DOI", (120, 92, 184)),
    ]
    status_label = "audit complete" if audit else "audit"
    draw.rounded_rectangle((x1 - 142, y0 + 12, x1 - 18, y0 + 31), radius=8, fill=(242, 246, 250), outline=(210, 218, 228), width=1)
    draw.text((x1 - 128, y0 + 15), status_label, fill=(88, 98, 112), font=_font(9, bold=True))
    for idx, (head, body, color) in enumerate(labels):
        col = idx % 2
        row = idx // 2
        bx = x0 + 18 + col * ((x1 - x0 - 50) // 2 + 14)
        by = y0 + 49 + row * 39
        bw = (x1 - x0 - 50) // 2
        draw.rounded_rectangle((bx, by, bx + bw, by + 30), radius=9, fill=(255, 255, 255), outline=color, width=2)
        draw.text((bx + 10, by + 8), head, fill=color, font=_font(11, bold=True))
        draw.text((bx + 60, by + 8), body, fill=(74, 86, 100), font=_font(10, bold=True))


def _draw_stage_spine(
    draw: ImageDraw.ImageDraw,
    stages: list[tuple[int, int, str, tuple[int, int, int]]],
    y: int,
) -> None:
    for idx, (x0, x1, label, color) in enumerate(stages):
        fill = _blend(color, (255, 255, 255), 0.82)
        draw.rounded_rectangle((x0, y, x1, y + 32), radius=12, fill=fill, outline=color, width=2)
        draw.text((x0 + 14, y + 8), label, fill=color, font=_font(13, bold=True))
        if idx < len(stages) - 1:
            mid_y = y + 16
            draw.line((x1 + 4, mid_y, stages[idx + 1][0] - 8, mid_y), fill=(156, 166, 180), width=2)
            draw.polygon([(stages[idx + 1][0] - 8, mid_y), (stages[idx + 1][0] - 18, mid_y - 6), (stages[idx + 1][0] - 18, mid_y + 6)], fill=(156, 166, 180))


def _draw_command_workflow(
    draw: ImageDraw.ImageDraw,
    xy: tuple[int, int, int, int],
    steps: list[tuple[str, str, tuple[int, int, int]]],
) -> None:
    x0, y0, x1, _ = xy
    step_h = 42
    gap = 18
    for idx, (command, detail, color) in enumerate(steps):
        y = y0 + idx * (step_h + gap)
        draw.rounded_rectangle((x0 + 4, y + 5, x1 + 4, y + step_h + 5), radius=12, fill=(232, 237, 243))
        draw.rounded_rectangle((x0, y, x1, y + step_h), radius=11, fill=(255, 255, 255), outline=color, width=2)
        draw.rounded_rectangle((x0 + 10, y + 10, x0 + 32, y + 32), radius=6, fill=_blend(color, (255, 255, 255), 0.75), outline=color, width=1)
        draw.text((x0 + 44, y + 7), command, fill=color, font=_font(14, bold=True))
        draw.text((x0 + 230, y + 9), detail, fill=(74, 86, 100), font=_font(12, bold=True))
        if idx < len(steps) - 1:
            mid_x = x0 + 20
            draw.line((mid_x, y + step_h + 3, mid_x, y + step_h + gap - 4), fill=(150, 161, 176), width=2)
            draw.polygon([(mid_x, y + step_h + gap - 2), (mid_x - 5, y + step_h + gap - 10), (mid_x + 5, y + step_h + gap - 10)], fill=(150, 161, 176))


def _draw_metric_strip(
    draw: ImageDraw.ImageDraw,
    xy: tuple[int, int, int, int],
    items: list[tuple[str, str, tuple[int, int, int]]],
) -> None:
    x0, y0, x1, y1 = xy
    item_w = (x1 - x0 - 10 * (len(items) - 1)) // max(len(items), 1)
    tall = (y1 - y0) >= 80
    value_size = 31 if tall else 22
    label_size = 15 if tall else 13
    label_y = y0 + 52 if tall else y0 + 38
    for idx, (value, label, color) in enumerate(items):
        bx = x0 + idx * (item_w + 10)
        fill = _blend(color, (255, 255, 255), 0.9 if tall else 0.94)
        draw.rounded_rectangle((bx + 4, y0 + 5, bx + item_w + 4, y1 + 5), radius=12, fill=(221, 228, 237))
        draw.rounded_rectangle((bx, y0, bx + item_w, y1), radius=11, fill=fill, outline=color, width=3 if tall else 2)
        draw.rounded_rectangle((bx + 8, y0 + 8, bx + 18, y1 - 8), radius=5, fill=color)
        text_x = bx + 30
        draw.text((text_x, y0 + 8), value, fill=color, font=_font(value_size, bold=True))
        draw.text((text_x, label_y), label, fill=(84, 96, 112), font=_font(label_size, bold=True))


