def _draw_hero_evidence_runway(
    draw: ImageDraw.ImageDraw,
    xy: tuple[int, int, int, int],
    cards: list[tuple[str, str, str, list[tuple[str, str, tuple[int, int, int]]], tuple[int, int, int]]],
) -> None:
    """Draw a high-impact claim-to-evidence belt for the Figure 1 first view."""
    x0, y0, x1, y1 = xy
    draw.rounded_rectangle((x0 + 8, y0 + 10, x1 + 8, y1 + 10), radius=22, fill=(190, 204, 218))
    draw.rounded_rectangle(xy, radius=21, fill=(18, 49, 76), outline=(117, 178, 199), width=3)
    draw.text((x0 + 34, y0 + 28), "First-view evidence", fill=(255, 255, 255), font=_font(31, bold=True))
    draw.text((x0 + 36, y0 + 74), "method innovation -> supervised benchmark -> biological interpretation", fill=(204, 228, 236), font=_font(17, bold=True))
    draw.rounded_rectangle((x0 + 34, y0 + 126, x0 + 316, y1 - 30), radius=18, fill=(255, 255, 255, 28), outline=(154, 202, 215), width=2)
    draw.rounded_rectangle((x0 + 52, y0 + 144, x0 + 298, y1 - 88), radius=15, fill=(10, 38, 62), outline=(130, 196, 214), width=2)
    draw.text((x0 + 70, y0 + 164), "Reviewer test", fill=(255, 255, 255), font=_font(21, bold=True))
    draw.rounded_rectangle((x0 + 70, y0 + 206, x0 + 278, y0 + 236), radius=10, fill=(255, 255, 255, 238), outline=(130, 196, 214), width=1)
    draw.text((x0 + 84, y0 + 214), "new method + real GT", fill=(18, 49, 76), font=_font(12, bold=True))
    draw.rounded_rectangle((x0 + 56, y1 - 78, x0 + 294, y1 - 44), radius=11, fill=(255, 255, 255, 235), outline=(190, 219, 228), width=2)
    draw.text((x0 + 76, y1 - 69), "not a module stack", fill=(23, 50, 78), font=_font(16, bold=True))
    card_x0 = x0 + 350
    gap = 20
    card_w = (x1 - card_x0 - 34 - gap * (len(cards) - 1)) // max(len(cards), 1)
    for idx, (kicker, title, body, metrics, color) in enumerate(cards):
        cx0 = card_x0 + idx * (card_w + gap)
        cx1 = cx0 + card_w
        draw.rounded_rectangle((cx0 + 5, y0 + 34 + 6, cx1 + 5, y1 - 30 + 6), radius=18, fill=(10, 25, 42, 72))
        draw.rounded_rectangle((cx0, y0 + 34, cx1, y1 - 30), radius=17, fill=(255, 255, 255), outline=color, width=4)
        draw.rounded_rectangle((cx0, y0 + 34, cx0 + 24, y1 - 30), radius=10, fill=color)
        draw.rounded_rectangle((cx0 + 42, y0 + 56, cx0 + 122, y0 + 94), radius=13, fill=_blend(color, (255, 255, 255), 0.82), outline=color, width=2)
        draw.text((cx0 + 58, y0 + 66), f"0{idx + 1}", fill=color, font=_font(19, bold=True))
        draw.text((cx0 + 142, y0 + 56), kicker.upper(), fill=color, font=_font(16, bold=True))
        draw.text((cx0 + 42, y0 + 104), title, fill=(18, 31, 48), font=_font(30, bold=True))
        _draw_wrapped(draw, (cx0 + 42, y0 + 148), body, _font(17), (61, 73, 89), card_w - 78, line_gap=5, max_lines=3)
        metric_y = y1 - 104
        metric_gap = 12
        metric_w = (card_w - 84 - metric_gap * (len(metrics) - 1)) // max(len(metrics), 1)
        for midx, (value, label, metric_color) in enumerate(metrics):
            mx0 = cx0 + 42 + midx * (metric_w + metric_gap)
            mx1 = mx0 + metric_w
            draw.rounded_rectangle((mx0, metric_y, mx1, metric_y + 56), radius=12, fill=_blend(metric_color, (255, 255, 255), 0.9), outline=metric_color, width=2)
            draw.rounded_rectangle((mx0 + 8, metric_y + 8, mx0 + 18, metric_y + 48), radius=5, fill=metric_color)
            draw.text((mx0 + 28, metric_y + 7), value, fill=metric_color, font=_font(18, bold=True))
            draw.text((mx0 + 28, metric_y + 33), _short_label(label, 16), fill=(74, 86, 101), font=_font(11, bold=True))


def _enhance_visual(image: Image.Image) -> Image.Image:
    image = image.convert("RGB")
    image = ImageEnhance.Color(image).enhance(1.18)
    image = ImageEnhance.Contrast(image).enhance(1.12)
    image = ImageEnhance.Sharpness(image).enhance(1.25)
    return image


def _rounded_paste(
    canvas: Image.Image,
    source: Image.Image,
    xy: tuple[int, int, int, int],
    radius: int = 16,
    fit: str = "cover",
) -> None:
    x0, y0, x1, y1 = xy
    size = (max(1, x1 - x0), max(1, y1 - y0))
    source = _enhance_visual(source)
    if fit == "contain":
        source.thumbnail(size, Image.Resampling.LANCZOS)
        tile = Image.new("RGB", size, (250, 252, 255))
        tile.paste(source, ((size[0] - source.width) // 2, (size[1] - source.height) // 2))
    else:
        tile = ImageOps.fit(source, size, method=Image.Resampling.LANCZOS)
    mask = Image.new("L", size, 0)
    mask_draw = ImageDraw.Draw(mask)
    mask_draw.rounded_rectangle((0, 0, size[0], size[1]), radius=radius, fill=255)
    canvas.paste(tile, (x0, y0), mask)


def _load_visual(path: str | Path, fallback_size: tuple[int, int] = (320, 220)) -> Image.Image:
    source = Path(path)
    if source.exists():
        try:
            return Image.open(source).convert("RGB")
        except Exception:
            pass
    image = Image.new("RGB", fallback_size, (245, 248, 252))
    draw = ImageDraw.Draw(image)
    draw.text((18, 18), "missing image", fill=(130, 60, 60), font=_font(18, bold=True))
    return image


def _glow_line(
    canvas: Image.Image,
    start: tuple[int, int],
    end: tuple[int, int],
    color: tuple[int, int, int],
    width: int = 5,
) -> None:
    overlay = Image.new("RGBA", canvas.size, (0, 0, 0, 0))
    odraw = ImageDraw.Draw(overlay)
    for scale, alpha in [(5, 28), (3, 48), (1, 210)]:
        odraw.line((start, end), fill=(*color, alpha), width=width * scale)
    canvas.alpha_composite(overlay)


def _glow_polyline(
    canvas: Image.Image,
    points: list[tuple[int, int]],
    color: tuple[int, int, int],
    width: int = 10,
    alpha: int = 170,
) -> None:
    if len(points) < 2:
        return
    overlay = Image.new("RGBA", canvas.size, (0, 0, 0, 0))
    odraw = ImageDraw.Draw(overlay)
    for scale, line_alpha in [(4, 24), (2, 54), (1, alpha)]:
        odraw.line(points, fill=(*color, line_alpha), width=width * scale, joint="curve")
    end = points[-1]
    prev = points[-2]
    angle = np.arctan2(end[1] - prev[1], end[0] - prev[0])
    size = max(16, width * 3)
    arrow = [
        end,
        (int(end[0] - size * np.cos(angle - 0.42)), int(end[1] - size * np.sin(angle - 0.42))),
        (int(end[0] - size * np.cos(angle + 0.42)), int(end[1] - size * np.sin(angle + 0.42))),
    ]
    odraw.polygon(arrow, fill=(*color, min(230, alpha + 30)))
    canvas.alpha_composite(overlay)


def _draw_thesis_belt(
    draw: ImageDraw.ImageDraw,
    xy: tuple[int, int, int, int],
    items: list[tuple[str, str, str, tuple[int, int, int]]],
) -> None:
    x0, y0, x1, y1 = xy
    gap = 18
    card_w = (x1 - x0 - gap * (len(items) - 1)) // max(len(items), 1)
    for idx, (kicker, title, body, color) in enumerate(items):
        cx0 = x0 + idx * (card_w + gap)
        cx1 = cx0 + card_w
        fill = _blend(color, (255, 255, 255), 0.87)
        draw.rounded_rectangle((cx0 + 6, y0 + 7, cx1 + 6, y1 + 7), radius=15, fill=(214, 222, 232))
        draw.rounded_rectangle((cx0, y0, cx1, y1), radius=14, fill=fill, outline=color, width=3)
        draw.rounded_rectangle((cx0, y0, cx0 + 18, y1), radius=8, fill=color)
        draw.text((cx0 + 34, y0 + 13), kicker.upper(), fill=color, font=_font(13, bold=True))
        draw.text((cx0 + 34, y0 + 36), title, fill=(21, 31, 46), font=_font(23, bold=True))
        _draw_wrapped(draw, (cx0 + 34, y0 + 64), body, _font(13), (63, 75, 91), cx1 - cx0 - 54, line_gap=1, max_lines=1)


def _draw_visual_gate(
    draw: ImageDraw.ImageDraw,
    center: tuple[int, int],
    radius: int,
    palette: dict[str, tuple[int, int, int]],
) -> None:
    cx, cy = center
    tri = [(cx, cy - radius), (cx - int(radius * 0.9), cy + int(radius * 0.62)), (cx + int(radius * 0.9), cy + int(radius * 0.62))]
    halo = [(cx, cy - radius - 18), (cx - int(radius * 1.04), cy + int(radius * 0.72)), (cx + int(radius * 1.04), cy + int(radius * 0.72))]
    draw.ellipse((cx - radius - 48, cy - radius - 18, cx + radius + 48, cy + radius + 38), fill=(248, 241, 248), outline=(226, 206, 220), width=3)
    for inset, color, width in [(30, palette["blue"], 5), (20, palette["green"], 5), (10, palette["purple"], 4)]:
        draw.arc(
            (cx - radius - inset, cy - radius - inset, cx + radius + inset, cy + radius + inset),
            205,
            332,
            fill=_blend(color, (255, 255, 255), 0.18),
            width=width,
        )
    draw.polygon(halo, fill=(255, 230, 240), outline=(232, 176, 198))
    draw.polygon(tri, fill=(255, 248, 251), outline=palette["rose"])
    draw.line((tri[0], tri[1]), fill=palette["rose"], width=8)
    draw.line((tri[1], tri[2]), fill=palette["rose"], width=8)
    draw.line((tri[2], tri[0]), fill=palette["rose"], width=8)
    vertex_labels = [
        ("ref", tri[0], palette["purple"]),
        ("H&E", tri[1], palette["blue"]),
        ("ST", tri[2], palette["green"]),
    ]
    for label, (vx, vy), color in vertex_labels:
        draw.ellipse((vx - 31, vy - 31, vx + 31, vy + 31), fill=(255, 255, 255), outline=color, width=5)
        draw.ellipse((vx - 17, vy - 17, vx + 17, vy + 17), fill=color, outline=(255, 255, 255), width=3)
        bbox = draw.textbbox((0, 0), label, font=_font(15, bold=True))
        lx = vx - (bbox[2] - bbox[0]) // 2
        ly = vy + 38
        draw.rounded_rectangle((lx - 8, ly - 3, lx + (bbox[2] - bbox[0]) + 8, ly + 20), radius=8, fill=(255, 255, 255), outline=color, width=2)
        draw.text((lx, ly), label, fill=color, font=_font(15, bold=True))
    draw.ellipse((cx - 62, cy - 62, cx + 62, cy + 62), fill=(255, 255, 255), outline=(232, 188, 204), width=6)
    draw.ellipse((cx - 48, cy - 48, cx + 48, cy + 48), fill=(27, 65, 99), outline=(255, 255, 255), width=5)
    for idx, word in enumerate(["TRUST", "GATE"]):
        bbox = draw.textbbox((0, 0), word, font=_font(21, bold=True))
        draw.text((cx - (bbox[2] - bbox[0]) // 2, cy - 24 + idx * 28), word, fill=(255, 255, 255), font=_font(21, bold=True))
    for angle, color in [(4.65, palette["purple"]), (2.6, palette["blue"]), (0.55, palette["green"])]:
        px = int(cx + np.cos(angle) * radius * 0.92)
        py = int(cy + np.sin(angle) * radius * 0.72)
        draw.ellipse((px - 12, py - 12, px + 12, py + 12), fill=color, outline=(255, 255, 255), width=3)


def _draw_method_visual_scene(
    canvas: Image.Image,
    draw: ImageDraw.ImageDraw,
    xy: tuple[int, int, int, int],
    palette: dict[str, tuple[int, int, int]],
    he_path: Path,
    image_gate_path: Path,
    reference_gate_path: Path,
    uncertainty_path: Path,
    boundary_path: Path,
    niche_path: Path,
    composition_path: Path,
    impact_metrics: list[tuple[str, str, tuple[int, int, int]]] | None = None,
) -> None:
    x0, y0, x1, y1 = xy
    he = _load_visual(he_path, (420, 300))
    scene_w, scene_h = x1 - x0, y1 - y0
    hero_tile = Image.new("RGBA", (scene_w, scene_h), (0, 0, 0, 0))
    hero_draw = ImageDraw.Draw(hero_tile)
    for x in range(scene_w):
        t = x / max(scene_w - 1, 1)
        if t < 0.35:
            color = _blend((255, 222, 240), (229, 244, 250), t / 0.35)
        elif t < 0.72:
            color = _blend((229, 244, 250), (235, 247, 242), (t - 0.35) / 0.37)
        else:
            color = _blend((235, 247, 242), (255, 244, 232), (t - 0.72) / 0.28)
        hero_draw.line((x, 0, x, scene_h), fill=(*color, 255))
    texture = ImageOps.fit(_enhance_visual(he), (scene_w, scene_h), method=Image.Resampling.LANCZOS).convert("RGBA")
    texture = ImageEnhance.Contrast(texture).enhance(1.18)
    texture_alpha = Image.new("L", (scene_w, scene_h), 48)
    texture.putalpha(texture_alpha)
    hero_tile.alpha_composite(texture)
    hero_draw.rounded_rectangle((18, 48, scene_w - 18, scene_h - 22), radius=26, fill=(16, 55, 86, 42), outline=(255, 255, 255, 100), width=2)
    hero_draw.polygon(
        [
            (scene_w * 0.30, 54),
            (scene_w * 0.50, 30),
            (scene_w * 0.72, scene_h - 58),
            (scene_w * 0.42, scene_h - 28),
        ],
        fill=(255, 255, 255, 48),
    )
    hero_draw.polygon(
        [
            (scene_w * 0.50, 74),
            (scene_w * 0.78, 44),
            (scene_w - 70, scene_h - 70),
            (scene_w * 0.68, scene_h - 34),
        ],
        fill=(57, 144, 156, 44),
    )
    glow = Image.new("RGBA", (scene_w, scene_h), (0, 0, 0, 0))
    gdraw = ImageDraw.Draw(glow)
    for idx in range(34):
        alpha = max(8, 92 - idx * 2)
        gdraw.arc((120 + idx * 18, -180 + idx * 5, scene_w - 30 - idx * 10, scene_h + 200 - idx * 4), 198, 336, fill=(57, 144, 156, alpha), width=5)
        if idx % 3 == 0:
            gdraw.arc((170 + idx * 12, -90 + idx * 3, scene_w - 210 - idx * 9, scene_h + 118 - idx * 3), 202, 332, fill=(194, 78, 112, max(8, alpha // 3)), width=3)
    hero_tile.alpha_composite(glow)
    hero_mask = Image.new("L", (scene_w, scene_h), 0)
    mask_draw = ImageDraw.Draw(hero_mask)
    mask_draw.rounded_rectangle((0, 0, scene_w, scene_h), radius=22, fill=255)
    canvas.paste(hero_tile, (x0, y0), hero_mask)

    scene = Image.new("RGBA", canvas.size, (0, 0, 0, 0))
    sdraw = ImageDraw.Draw(scene)
    sdraw.rounded_rectangle(xy, radius=22, fill=(255, 255, 255, 22), outline=(150, 178, 202, 255), width=5)
    for idx in range(22):
        alpha = 52 - idx
        sdraw.arc((x0 + 220 + idx * 15, y0 - 130 + idx * 5, x1 - 40 - idx * 8, y1 + 160 - idx * 5), 196, 338, fill=(57, 144, 156, max(alpha, 10)), width=4)
        if idx % 3 == 0:
            sdraw.arc((x0 + 260 + idx * 13, y0 - 84 + idx * 4, x1 - 160 - idx * 7, y1 + 122 - idx * 4), 198, 334, fill=(194, 78, 112, max(alpha // 2, 7)), width=2)
    canvas.alpha_composite(scene)

    claim = Image.new("RGBA", canvas.size, (0, 0, 0, 0))
    cdraw = ImageDraw.Draw(claim)
    cdraw.rounded_rectangle((x0 + 46, y0 + 44, x1 - 46, y0 + 116), radius=20, fill=(19, 58, 94, 224), outline=(210, 236, 244, 160), width=2)
    cdraw.rounded_rectangle((x0 + 68, y0 + 60, x0 + 314, y0 + 100), radius=13, fill=(255, 255, 255, 238))
    canvas.alpha_composite(claim)
    draw.text((x0 + 94, y0 + 68), "Core claim", fill=(19, 58, 94), font=_font(20, bold=True))
    draw.text(
        (x0 + 346, y0 + 58),
        "H&E + ST + scRNA reference become calibrated cell-type proportions, uncertainty and tissue niches",
        fill=(255, 255, 255),
        font=_font(30, bold=True),
    )

    ribbon_box = (x0 + 30, y0 + 116, x0 + 1640, y0 + 562)
    ribbon_w, ribbon_h = ribbon_box[2] - ribbon_box[0], ribbon_box[3] - ribbon_box[1]
    ribbon_texture = ImageOps.fit(_enhance_visual(he), (ribbon_w, ribbon_h), method=Image.Resampling.LANCZOS).convert("RGBA")
    ribbon_alpha = Image.new("L", (ribbon_w, ribbon_h), 0)
    rdraw = ImageDraw.Draw(ribbon_alpha)
    rdraw.polygon(
        [
            (0, 42),
            (ribbon_w - 170, 8),
            (ribbon_w, ribbon_h // 2),
            (ribbon_w - 150, ribbon_h - 8),
            (0, ribbon_h - 48),
        ],
        fill=118,
    )
    for idx in range(16):
        rdraw.arc((idx * 42, -60 + idx * 4, ribbon_w - idx * 36, ribbon_h + 80 - idx * 2), 190, 350, fill=max(46, 112 - idx * 3), width=4)
    ribbon_texture.putalpha(ribbon_alpha)
