def _paste_thumbnail(
    canvas: Image.Image,
    draw: ImageDraw.ImageDraw,
    source_path: str | Path,
    xy: tuple[int, int, int, int],
    label: str,
    outline: tuple[int, int, int] = (185, 194, 205),
    fit: str = "cover",
) -> None:
    x0, y0, x1, y1 = xy
    draw.rounded_rectangle(xy, radius=12, fill=(248, 250, 252), outline=outline, width=2)
    source = Path(source_path)
    inner = (x1 - x0 - 12, y1 - y0 - 42)
    if source.exists() and inner[0] > 8 and inner[1] > 8:
        try:
            image = Image.open(source).convert("RGB")
            if fit == "contain":
                image.thumbnail(inner, Image.Resampling.LANCZOS)
                tile = Image.new("RGB", inner, (250, 252, 255))
                tile.paste(image, ((inner[0] - image.width) // 2, (inner[1] - image.height) // 2))
            else:
                tile = ImageOps.fit(image, inner, method=Image.Resampling.LANCZOS)
            canvas.paste(tile, (x0 + 6, y0 + 6))
        except Exception:
            _draw_wrapped(draw, (x0 + 16, y0 + 28), "image unavailable", _font(15), (120, 55, 55), x1 - x0 - 32, line_gap=3, max_lines=2)
    else:
        _draw_wrapped(draw, (x0 + 16, y0 + 28), "image unavailable", _font(15), (120, 55, 55), x1 - x0 - 32, line_gap=3, max_lines=2)
    draw.rectangle((x0 + 6, y1 - 34, x1 - 6, y1 - 6), fill=(255, 255, 255))
    draw.text((x0 + 14, y1 - 30), label, fill=(35, 45, 60), font=_font(16, bold=True))


def _draw_heatmap_icon(
    draw: ImageDraw.ImageDraw,
    xy: tuple[int, int, int, int],
    label: str,
    palette: list[tuple[int, int, int]],
    rows: int = 9,
    cols: int = 11,
) -> None:
    x0, y0, x1, y1 = xy
    draw.rounded_rectangle(xy, radius=12, fill=(248, 250, 252), outline=(205, 212, 222), width=2)
    rng = np.random.default_rng(11)
    left, top = x0 + 12, y0 + 12
    cell_w = max(4, (x1 - x0 - 24) // cols)
    cell_h = max(4, (y1 - y0 - 46) // rows)
    values = rng.random((rows, cols))
    for row in range(rows):
        for col in range(cols):
            color = palette[int(values[row, col] * (len(palette) - 1))]
            draw.rectangle((left + col * cell_w, top + row * cell_h, left + (col + 1) * cell_w - 2, top + (row + 1) * cell_h - 2), fill=color)
    draw.text((x0 + 14, y1 - 30), label, fill=(35, 45, 60), font=_font(16, bold=True))


def _draw_cell_scatter_icon(draw: ImageDraw.ImageDraw, xy: tuple[int, int, int, int], label: str) -> None:
    x0, y0, x1, y1 = xy
    draw.rounded_rectangle(xy, radius=12, fill=(248, 250, 252), outline=(205, 212, 222), width=2)
    rng = np.random.default_rng(23)
    colors = [(45, 126, 168), (205, 132, 45), (120, 92, 184), (72, 148, 107), (194, 78, 112)]
    for _ in range(150):
        cx = int(rng.uniform(x0 + 18, x1 - 18))
        cy = int(rng.uniform(y0 + 16, y1 - 44))
        color = colors[int(rng.integers(0, len(colors)))]
        draw.ellipse((cx - 3, cy - 3, cx + 3, cy + 3), fill=color)
    for cx, cy in [(x0 + 62, y0 + 68), (x0 + 134, y0 + 94), (x0 + 104, y0 + 132)]:
        draw.ellipse((cx - 28, cy - 28, cx + 28, cy + 28), outline=(211, 121, 47), width=3)
    draw.text((x0 + 14, y1 - 30), label, fill=(35, 45, 60), font=_font(16, bold=True))


def _draw_spatial_atlas(
    draw: ImageDraw.ImageDraw,
    xy: tuple[int, int, int, int],
    label: str,
    outline: tuple[int, int, int],
    coords_path: str | Path = "data/processed/cytassist_xenium_rep2_common297/spot_coords.csv",
    proportions_path: str | Path = "results/nature_main/cytassist_rep2_radius55/predicted_proportions.csv",
) -> None:
    x0, y0, x1, y1 = xy
    draw.rounded_rectangle((x0 + 5, y0 + 6, x1 + 5, y1 + 6), radius=16, fill=(232, 237, 243))
    draw.rounded_rectangle(xy, radius=15, fill=(252, 254, 255), outline=outline, width=3)
    coords = _load_csv(coords_path)
    props = _load_csv(proportions_path)
    if coords.empty or props.empty or "spot_id" not in coords or "spot_id" not in props:
        _draw_spot_map(draw, xy)
        return
    merged = coords.merge(props, on="spot_id", how="inner")
    if "in_tissue" in merged:
        merged = merged.loc[merged["in_tissue"].astype(int).eq(1)].copy()
    if merged.empty:
        _draw_spot_map(draw, xy)
        return
    groups = {
        "tumor": ["Invasive Tumor", "Prolif Invasive Tumor", "DCIS 1", "DCIS 2", "T Cell & Tumor Hybrid"],
        "stroma": ["Stromal", "Perivascular-Like", "Endothelial", "Stromal & T Cell Hybrid"],
        "immune": ["B Cells", "CD4+ T Cells", "CD8+ T Cells", "IRF7+ DCs", "LAMP3+ DCs", "Macrophages 1", "Macrophages 2", "Mast Cells"],
        "ductal": ["Myoepi ACTA2+", "Myoepi KRT15+"],
    }
    group_colors = {
        "tumor": (194, 78, 112),
        "stroma": (72, 148, 107),
        "immune": (58, 121, 176),
        "ductal": (207, 132, 40),
        "other": (120, 92, 184),
    }
    scores = {}
    for group, cols in groups.items():
        present = [col for col in cols if col in merged.columns]
        scores[group] = merged[present].sum(axis=1).to_numpy() if present else np.zeros(len(merged))
    matrix = np.vstack([scores[key] for key in ["tumor", "stroma", "immune", "ductal"]]).T
    dominant_idx = np.argmax(matrix, axis=1)
    dominant_score = np.max(matrix, axis=1)
    group_names = np.array(["tumor", "stroma", "immune", "ductal"], dtype=object)
    dominant = np.where(dominant_score > 0.02, group_names[dominant_idx], "other")
    xs = merged["x"].astype(float).to_numpy()
    ys = merged["y"].astype(float).to_numpy()
    xs = (xs - xs.min()) / max(xs.max() - xs.min(), 1.0)
    ys = (ys - ys.min()) / max(ys.max() - ys.min(), 1.0)
    pad_x, pad_y = 34, 28
    plot_y1 = y1 - 46
    draw.rounded_rectangle((x0 + 18, y0 + 18, x1 - 18, plot_y1), radius=12, fill=(247, 249, 252), outline=(224, 230, 237), width=1)
    point_scale = max(3, int(min(x1 - x0, plot_y1 - y0) / 92))
    for px, py, group, score in zip(xs, ys, dominant, dominant_score):
        cx = int(x0 + pad_x + px * (x1 - x0 - 2 * pad_x))
        cy = int(y0 + pad_y + py * (plot_y1 - y0 - 2 * pad_y))
        color = group_colors.get(str(group), group_colors["other"])
        r = point_scale + (1 if score > 0.65 else 0)
        draw.ellipse((cx - r, cy - r, cx + r, cy + r), fill=color, outline=(255, 255, 255))
    draw.text((x0 + 18, y1 - 34), label, fill=(35, 45, 60), font=_font(17, bold=True))
    legend = [("tumor", group_colors["tumor"]), ("stroma", group_colors["stroma"]), ("immune", group_colors["immune"]), ("ductal", group_colors["ductal"])]
    lx = x1 - 328
    for idx, (name, color) in enumerate(legend):
        tx = lx + idx * 78
        draw.rounded_rectangle((tx, y1 - 34, tx + 18, y1 - 16), radius=4, fill=color)
        draw.text((tx + 23, y1 - 36), name[:3], fill=(74, 86, 100), font=_font(12, bold=True))


def _draw_group_triptych(
    draw: ImageDraw.ImageDraw,
    xy: tuple[int, int, int, int],
    label: str,
    outline: tuple[int, int, int],
    coords_path: str | Path = "data/processed/cytassist_xenium_rep2_common297/spot_coords.csv",
    proportions_path: str | Path = "results/nature_main/cytassist_rep2_radius55/predicted_proportions.csv",
) -> None:
    x0, y0, x1, y1 = xy
    draw.rounded_rectangle((x0 + 5, y0 + 6, x1 + 5, y1 + 6), radius=14, fill=(232, 237, 243))
    draw.rounded_rectangle(xy, radius=13, fill=(252, 254, 255), outline=outline, width=3)
    coords = _load_csv(coords_path)
    props = _load_csv(proportions_path)
    if coords.empty or props.empty or "spot_id" not in coords or "spot_id" not in props:
        _draw_heatmap_icon(draw, xy, label, [(239, 250, 251), outline], rows=6, cols=9)
        return
    merged = coords.merge(props, on="spot_id", how="inner")
    if "in_tissue" in merged:
        merged = merged.loc[merged["in_tissue"].astype(int).eq(1)].copy()
    xs = merged["x"].astype(float).to_numpy()
    ys = merged["y"].astype(float).to_numpy()
    xs = (xs - xs.min()) / max(xs.max() - xs.min(), 1.0)
    ys = (ys - ys.min()) / max(ys.max() - ys.min(), 1.0)
    groups = [
        ("tumor", ["Invasive Tumor", "Prolif Invasive Tumor", "DCIS 1", "DCIS 2", "T Cell & Tumor Hybrid"], (194, 78, 112)),
        ("stroma", ["Stromal", "Perivascular-Like", "Endothelial", "Stromal & T Cell Hybrid"], (72, 148, 107)),
        ("immune", ["B Cells", "CD4+ T Cells", "CD8+ T Cells", "IRF7+ DCs", "LAMP3+ DCs", "Macrophages 1", "Macrophages 2", "Mast Cells"], (58, 121, 176)),
    ]
    inner_x0, inner_y0 = x0 + 14, y0 + 12
    map_w = (x1 - x0 - 50) // 3
    map_h = y1 - y0 - 54
    for idx, (name, cols, color) in enumerate(groups):
        mx0 = inner_x0 + idx * (map_w + 10)
        my0 = inner_y0
        mx1 = mx0 + map_w
        my1 = my0 + map_h
        draw.rounded_rectangle((mx0, my0, mx1, my1), radius=9, fill=(247, 249, 252), outline=(224, 230, 237), width=1)
        present = [col for col in cols if col in merged.columns]
        score = merged[present].sum(axis=1).to_numpy() if present else np.zeros(len(merged))
        if score.max() > 0:
            score = score / score.max()
        for px, py, val in zip(xs, ys, score):
            cx = int(mx0 + 9 + px * (map_w - 18))
            cy = int(my0 + 8 + py * (map_h - 16))
            if val < 0.03:
                fill = (215, 222, 230)
                r = 1
            else:
                fill = tuple(int(245 * (1 - val) + c * val) for c in color)
                r = 2
            draw.ellipse((cx - r, cy - r, cx + r, cy + r), fill=fill)
        draw.text((mx0 + 8, my1 - 19), name[:3], fill=color, font=_font(11, bold=True))
    draw.text((x0 + 14, y1 - 30), label, fill=(35, 45, 60), font=_font(16, bold=True))


def _draw_wavelet_tiles(draw: ImageDraw.ImageDraw, xy: tuple[int, int, int, int]) -> None:
    x0, y0, x1, y1 = xy
    draw.rounded_rectangle(xy, radius=12, fill=(250, 252, 255), outline=(58, 121, 176), width=2)
    labels = ["LL", "LH", "HL", "HH"]
    fills = [(221, 236, 248), (240, 247, 253), (229, 242, 250), (217, 232, 243)]
    tile_w = (x1 - x0 - 36) // 2
    tile_h = (y1 - y0 - 54) // 2
    for idx, lab in enumerate(labels):
        col, row = idx % 2, idx // 2
        tx = x0 + 12 + col * (tile_w + 12)
        ty = y0 + 12 + row * (tile_h + 10)
        draw.rectangle((tx, ty, tx + tile_w, ty + tile_h), fill=fills[idx], outline=(138, 166, 192), width=1)
        for step in range(7):
            offset = step * max(6, tile_w // 8)
            if lab == "LH":
                draw.line((tx + offset, ty + 4, tx + offset, ty + tile_h - 4), fill=(58, 121, 176), width=1)
            elif lab == "HL":
                draw.line((tx + 4, ty + offset, tx + tile_w - 4, ty + offset), fill=(58, 121, 176), width=1)
            elif lab == "HH":
                draw.line((tx + offset, ty + 4, tx + 4, ty + offset), fill=(58, 121, 176), width=1)
        draw.text((tx + 8, ty + 6), lab, fill=(35, 45, 60), font=_font(14, bold=True))
    draw.text((x0 + 12, y1 - 30), "wavelet bands", fill=(35, 45, 60), font=_font(16, bold=True))


def _draw_agent_network(draw: ImageDraw.ImageDraw, xy: tuple[int, int, int, int], palette: dict[str, tuple[int, int, int]]) -> None:
    x0, y0, x1, y1 = xy
    draw.rounded_rectangle(xy, radius=12, fill=(250, 248, 255), outline=palette["purple"], width=2)
    centers = [(x0 + 48, y0 + 44), (x0 + 104, y0 + 34), (x0 + 154, y0 + 62), (x0 + 70, y0 + 112), (x0 + 142, y0 + 122)]
    target = (x1 - 54, y0 + 86)
    for center in centers:
        draw.line((center[0], center[1], target[0], target[1]), fill=(176, 160, 211), width=3)
    for idx, center in enumerate(centers):
        color = [palette["purple"], palette["blue"], palette["green"], palette["orange"], palette["rose"]][idx]
        draw.ellipse((center[0] - 18, center[1] - 18, center[0] + 18, center[1] + 18), fill=color, outline=(80, 89, 102), width=1)
    draw.ellipse((target[0] - 26, target[1] - 26, target[0] + 26, target[1] + 26), fill=(255, 255, 255), outline=palette["purple"], width=3)
    draw.text((target[0] - 14, target[1] - 10), "A", fill=palette["purple"], font=_font(20, bold=True))
    draw.text((x0 + 12, y1 - 30), "prototype agents", fill=(35, 45, 60), font=_font(16, bold=True))


def _draw_gate_simplex(draw: ImageDraw.ImageDraw, xy: tuple[int, int, int, int], palette: dict[str, tuple[int, int, int]]) -> None:
    x0, y0, x1, y1 = xy
    draw.rounded_rectangle(xy, radius=12, fill=(255, 248, 250), outline=palette["rose"], width=2)
    tri = [(x0 + 42, y1 - 48), (x1 - 42, y1 - 48), ((x0 + x1) // 2, y0 + 32)]
    draw.polygon(tri, outline=palette["rose"], fill=(255, 244, 247))
    draw.text((tri[0][0] - 18, tri[0][1] + 6), "img", fill=palette["blue"], font=_font(14, bold=True))
    draw.text((tri[1][0] - 20, tri[1][1] + 6), "expr", fill=palette["green"], font=_font(14, bold=True))
    draw.text((tri[2][0] - 18, tri[2][1] - 26), "ref", fill=palette["purple"], font=_font(14, bold=True))
    dot = (int(x0 + 0.63 * (x1 - x0)), int(y0 + 0.56 * (y1 - y0)))
    draw.ellipse((dot[0] - 10, dot[1] - 10, dot[0] + 10, dot[1] + 10), fill=palette["rose"], outline=(255, 255, 255), width=2)
    draw.text((x0 + 14, y1 - 28), "reliability gate", fill=(35, 45, 60), font=_font(16, bold=True))


def _write_overview_schematic(path: Path, run_dir: Path | None = None, tables_dir: Path | None = None) -> None:
    run_dir = run_dir or DEFAULT_RUN_DIR
    tables_dir = tables_dir or DEFAULT_TABLES_DIR
    width, height = 3600, 3650
    image = Image.new("RGBA", (width, height), (247, 249, 252, 255))
    bg = Image.new("RGBA", (width, height), (0, 0, 0, 0))
    bg_draw = ImageDraw.Draw(bg)
    for idx in range(22):
        inset = idx * 28
        alpha = max(8, 48 - idx * 2)
        bg_draw.arc((120 + inset, 95 + idx * 3, width - 130 - inset, 680 - idx * 6), 184, 350, fill=(74, 166, 186, alpha), width=4)
        bg_draw.arc((180 + inset, 500 + idx * 5, width - 220 - inset, 1080 + idx * 4), 196, 340, fill=(166, 114, 196, max(5, alpha - 14)), width=3)
    bg_draw.ellipse((width - 860, 40, width - 110, 430), fill=(255, 176, 112, 18))
    bg_draw.ellipse((85, 760, 760, 1260), fill=(82, 149, 210, 15))
    image.alpha_composite(bg)
    draw = ImageDraw.Draw(image)
    header_x0, header_y0, header_x1, header_y1 = 72, 28, width - 72, 190
    header = Image.new("RGBA", (header_x1 - header_x0, header_y1 - header_y0), (0, 0, 0, 0))
    hdraw = ImageDraw.Draw(header)
    for x in range(header.width):
        t = x / max(header.width - 1, 1)
        c0 = np.array([38, 88, 139])
        c1 = np.array([77, 160, 184])
        color = tuple((c0 * (1 - t) + c1 * t).astype(int))
        hdraw.line((x, 0, x, header.height), fill=(*color, 242))
    for idx in range(28):
        yy = 30 + idx * 5
        hdraw.arc((60 + idx * 18, yy - 70, header.width - 120 - idx * 10, yy + 230), 190, 350, fill=(255, 255, 255, max(18, 75 - idx * 2)), width=3)
    rng_header = np.random.default_rng(101)
    for _ in range(90):
        px = int(rng_header.uniform(120, header.width - 120))
        py = int(rng_header.uniform(32, header.height - 28))
        rr = int(rng_header.integers(2, 6))
        hdraw.ellipse((px - rr, py - rr, px + rr, py + rr), fill=(255, 255, 255, int(rng_header.integers(28, 72))))
    mask = Image.new("L", header.size, 0)
    mask_draw = ImageDraw.Draw(mask)
    mask_draw.rounded_rectangle((0, 0, header.width, header.height), radius=28, fill=255)
    image.paste(header, (header_x0, header_y0), mask)
    draw.rounded_rectangle((header_x0, header_y0, header_x1, header_y1), radius=28, outline=(190, 213, 226), width=2)
    icon_x, icon_y = header_x0 + 28, header_y0 + 26
    draw.rounded_rectangle((icon_x, icon_y, icon_x + 116, icon_y + 116), radius=22, fill=(255, 255, 255, 232), outline=(220, 235, 243), width=2)
    for idx, color in enumerate([(194, 78, 112), (58, 121, 176), (72, 148, 107), (120, 92, 184)]):
        cx = icon_x + 36 + (idx % 2) * 42
        cy = icon_y + 38 + (idx // 2) * 42
        draw.ellipse((cx - 13, cy - 13, cx + 13, cy + 13), fill=color, outline=(255, 255, 255), width=3)
    draw.line((icon_x + 49, icon_y + 38, icon_x + 78, icon_y + 80), fill=(72, 88, 111), width=3)
