    gauge = (effect[0] + 414, effect[1] + 150, effect[2] - 56, effect[1] + 244)
    gauge_max = max(next_jsd * 1.08, best_jsd + 1e-6)
    gx0, gy, gx1 = gauge[0], gauge[1] + 52, gauge[2]
    best_pos = int(gx0 + (best_jsd / gauge_max) * (gx1 - gx0))
    next_pos = int(gx0 + (next_jsd / gauge_max) * (gx1 - gx0))
    draw.rounded_rectangle((gx0, gy - 16, gx1, gy + 16), radius=12, fill=(255, 255, 255, 38), outline=(146, 190, 206), width=2)
    draw.rounded_rectangle((best_pos, gy - 15, max(next_pos, best_pos + 12), gy + 15), radius=10, fill=(255, 201, 116), outline=None)
    draw.line((gx0, gy, gx1, gy), fill=(232, 241, 246), width=3)
    draw.ellipse((best_pos - 18, gy - 18, best_pos + 18, gy + 18), fill=palette["red"], outline=(255, 255, 255), width=3)
    draw.ellipse((next_pos - 18, gy - 18, next_pos + 18, gy + 18), fill=palette["orange"], outline=(255, 255, 255), width=3)
    draw.text((max(gx0, best_pos - 12), gy - 50), "WaveST-Gate", fill=(255, 232, 238), font=_font(10, bold=True))
    draw.text((max(gx0 + 130, next_pos - 50), gy - 50), "next best", fill=(255, 224, 188), font=_font(10, bold=True))
    draw.text((gx0, gy + 30), "JSD gap gauge: lower is better", fill=(205, 225, 234), font=_font(10, bold=True))
    draw.rounded_rectangle((effect[0] + 28, effect[1] + 258, effect[2] - 28, effect[1] + 354), radius=18, fill=(255, 246, 232), outline=palette["orange"], width=2)
    draw.text((effect[0] + 54, effect[1] + 270), f"{fold:.1f}x", fill=palette["orange"], font=_font(43, bold=True))
    draw.text((effect[0] + 218, effect[1] + 284), "lower raw JSD\nthan next best", fill=palette["orange"], font=_font(16, bold=True), spacing=2)
    draw.rounded_rectangle((effect[0] + 28, effect[1] + 376, effect[2] - 28, effect[3] - 24), radius=16, fill=(255, 255, 255), outline=(158, 204, 218), width=2)
    draw.text((effect[0] + 48, effect[1] + 392), "fair benchmark contract", fill=palette["teal"], font=_font(17, bold=True))
    draw.text((effect[0] + 48, effect[1] + 426), "same spots | same genes | same reference", fill=(45, 63, 82), font=_font(13, bold=True))

    perf = (ax0 + 38, ay0 + 730, ax1 - 38, ay1 - 38)
