    fbox = (perf[0] + 2250, perf[1] + 54, perf[2] - 22, perf[3] - 22)
    draw.rounded_rectangle(fbox, radius=12, fill=(246, 252, 248), outline=palette["green"], width=2)
    draw.text((fbox[0] + 16, fbox[1] + 12), "paired bootstrap improvement forest", fill=palette["green"], font=_font(14, bold=True))
    fplot = (fbox[0] + 156, fbox[1] + 46, fbox[2] - 50, fbox[3] - 34)
    draw.line((fplot[0], fplot[3], fplot[2], fplot[3]), fill=(148, 162, 178), width=2)
    for frac in np.linspace(0, 1, 4):
        x = int(fplot[0] + frac * (fplot[2] - fplot[0]))
        draw.line((x, fplot[1], x, fplot[3]), fill=palette["grid"], width=1)
    forest = bootstrap.copy()
    metric_col = "mean_jsd_improvement_vs_wavestgate"
    for col in [metric_col, "ci95_low", "ci95_high", "bootstrap_p_baseline_not_worse"]:
        if col not in forest.columns:
            forest[col] = np.nan
        forest[col] = pd.to_numeric(forest[col], errors="coerce")
    forest = forest.dropna(subset=[metric_col]).sort_values(metric_col, ascending=False).head(6).reset_index(drop=True)
    max_hi = max(float(forest["ci95_high"].max()) if not forest.empty else 0.5, 0.05)
    fh = (fplot[3] - fplot[1]) / max(len(forest), 1)
    for idx, row in forest.iterrows():
        y = int(fplot[1] + (idx + 0.5) * fh)
        val = as_float(row.get(metric_col), 0.0)
        lo = max(0.0, as_float(row.get("ci95_low"), val))
        hi = max(lo, as_float(row.get("ci95_high"), val))
        x = int(fplot[0] + (val / max_hi) * (fplot[2] - fplot[0]))
        xlo = int(fplot[0] + (lo / max_hi) * (fplot[2] - fplot[0]))
        xhi = int(fplot[0] + (hi / max_hi) * (fplot[2] - fplot[0]))
        draw.text((fbox[0] + 16, y - 9), _short_label(str(row.get("method", "baseline")), 18), fill=palette["ink"], font=_font(9, bold=True))
        draw.line((xlo, y, xhi, y), fill=palette["green"], width=3)
        draw.polygon([(x, y - 8), (x + 8, y), (x, y + 8), (x - 8, y)], fill=palette["green"], outline=(255, 255, 255))
        draw.text((fplot[2] + 14, y - 9), p_stars(as_float(row.get("bootstrap_p_baseline_not_worse"), np.nan)), fill=palette["green"], font=_font(9, bold=True))

    # B: Rep1 external adaptation.
    spine = (62, 1420, width - 62, 1442)
