    curve = (bx0 + 42, by0 + 116, bx1 - 42, by0 + 520)
    draw.rounded_rectangle((curve[0] + 5, curve[1] + 6, curve[2] + 5, curve[3] + 6), radius=15, fill=(218, 226, 235))
    draw.rounded_rectangle(curve, radius=14, fill=(250, 252, 255), outline=palette["orange"], width=2)
    xs = retune["budget_steps"].to_numpy(dtype=float)
    ys = retune["jsd"].to_numpy(dtype=float)
