    px0, py0, px1, py1 = curve[0] + 58, curve[1] + 56, curve[2] - 38, curve[3] - 58
    ylo = min(float(np.nanmin(ys)), baseline_line) * 0.82
    yhi = max(float(np.nanmax(ys)), baseline_line) * 1.08
    for frac in np.linspace(0, 1, 5):
        y = int(py1 - frac * (py1 - py0))
        draw.line((px0, y, px1, y), fill=palette["grid"], width=1)
    draw.line((px0, py1, px1, py1), fill=(149, 162, 178), width=2)
    draw.line((px0, py0, px0, py1), fill=(149, 162, 178), width=2)

    def rx(value: float) -> int:
        return int(px0 + (np.log10(value + 1) / np.log10(max(float(np.nanmax(xs)), 1.0) + 1)) * (px1 - px0))

    def ry(value: float) -> int:
        return int(py1 - (value - ylo) / max(yhi - ylo, 1e-9) * (py1 - py0))

    base_y = ry(baseline_line)
    draw.line((px0, base_y, px1, base_y), fill=palette["red"], width=3)
    draw.text((px0 + 8, base_y - 25), f"best baseline {baseline_line:.3f}", fill=palette["red"], font=_font(10, bold=True))
    pts = [(rx(float(x)), ry(float(y))) for x, y in zip(xs, ys)]
