    draw.text((cohort[0] + 18, cohort[1] + 14), "two-sample mean JSD", fill=palette["ink"], font=_font(16, bold=True))
    for ci, (label, frame, color) in enumerate([("no retune", multi_no, palette["rose"]), ("minimal", multi_rt, palette["teal"])]):
        sub = frame.copy()
