        sub["jsd_mean"] = pd.to_numeric(sub["jsd_mean"], errors="coerce")
        sub = sub.dropna(subset=["jsd_mean"]).sort_values("jsd_mean").head(4)
        x0 = cohort[0] + 18 + ci * ((cohort[2] - cohort[0] - 54) // 2 + 18)
        x1 = x0 + (cohort[2] - cohort[0] - 72) // 2
        draw.text((x0, cohort[1] + 48), label, fill=color, font=_font(12, bold=True))
        max_v = max(float(sub["jsd_mean"].max()) if not sub.empty else 0.1, 1e-6)
        for ri, row in sub.reset_index(drop=True).iterrows():
            y = cohort[1] + 76 + ri * 34
