    center_text((head[0], head[1] + 45, head[2], head[1] + 78), "matched GT | Rep1 direct | minimal retune | mean index", _font(16, bold=True), palette["red"])
    winner_chip = (head[2] - 390, head[1] + 18, head[2] - 34, head[1] + 74)
