        finite = vals[np.isfinite(vals)]
        lo = float(finite.min()) if finite.size else 0.0
        hi = float(finite.max()) if finite.size else 1.0
        score = np.full_like(vals, np.nan, dtype=float)
        if hi > lo:
            score = 1.0 - (vals - lo) / (hi - lo)
        elif finite.size:
            score = np.where(np.isfinite(vals), 1.0, np.nan)
        score_col = f"{col}_score"
        assessment[score_col] = np.clip(score, 0.0, 1.0)
