    center_text((wh[0] + 258, wh[1] + 12, wh[2] - 302, wh[1] + 58), "Comprehensive Assessment of 13 Methods", _font(29, bold=True), palette["ink"])
    center_text((wh[0] + 258, wh[1] + 62, wh[2] - 302, wh[1] + 104), "matched GT | Rep1 direct | minimal retune | normalized mean index", _font(15, bold=True), palette["red"])
