    if not coords_c.empty and not errors_c.empty and {"spot_id", "x", "y"}.issubset(coords_c.columns):
        coords_c = coords_c.copy()
        errors_c = errors_c.copy()
        coords_c["x"] = pd.to_numeric(coords_c["x"], errors="coerce")
        coords_c["y"] = pd.to_numeric(coords_c["y"], errors="coerce")
        errors_c["jsd"] = pd.to_numeric(errors_c.get("jsd", pd.Series(dtype=float)), errors="coerce")
        spatial_c = errors_c.merge(coords_c[["spot_id", "x", "y"]], on="spot_id", how="inner").dropna(subset=["x", "y"])
        if not spatial_c.empty:
            def c_major_group(label: Any) -> str:
                text = str(label)
                if any(key in text for key in ["Tumor", "DCIS", "Invasive"]):
                    return "Tumor"
                if any(key in text for key in ["T Cell", "T Cells", "B Cells", "Macrophages", "DCs", "Mast"]):
                    return "Immune"
                if any(key in text for key in ["Stromal", "Perivascular"]):
                    return "Stroma"
                if "Endothelial" in text:
                    return "Endothelial"
                if "Myoepi" in text:
                    return "Myoepi"
                return "Other"

            c_group_colors = {
                "Tumor": palette["red"],
                "Immune": palette["purple"],
                "Stroma": palette["teal"],
                "Endothelial": palette["blue"],
                "Myoepi": palette["orange"],
                "Other": (128, 142, 160),
            }
            c_jsd = spatial_c["jsd"].to_numpy(dtype=float)
            c_match = (
                float((spatial_c["dominant_gt"].astype(str) == spatial_c["dominant_pred"].astype(str)).mean())
                if {"dominant_gt", "dominant_pred"}.issubset(spatial_c.columns)
                else np.nan
            )
            c_median = float(np.nanmedian(c_jsd)) if np.isfinite(c_jsd).any() else np.nan
            c_q90 = float(np.nanpercentile(c_jsd, 90)) if np.isfinite(c_jsd).any() else np.nan
            c_jlo = float(np.nanpercentile(c_jsd, 5)) if np.isfinite(c_jsd).any() else 0.0
            c_jhi = float(np.nanpercentile(c_jsd, 95)) if np.isfinite(c_jsd).any() else 1.0
            xmin, xmax = float(spatial_c["x"].min()), float(spatial_c["x"].max())
            ymin, ymax = float(spatial_c["y"].min()), float(spatial_c["y"].max())
            xpad = max((xmax - xmin) * 0.08, 1.0)
            ypad = max((ymax - ymin) * 0.08, 1.0)
            xmin, xmax = xmin - xpad, xmax + xpad
            ymin, ymax = ymin - ypad, ymax + ypad
            draw.rounded_rectangle((c_body[0] + 7, c_body[1] + 8, c_body[2] + 7, c_body[3] + 8), radius=22, fill=(190, 204, 218))
            draw.rounded_rectangle(c_body, radius=21, fill=(252, 254, 255), outline=palette["purple"], width=3)
            c_head = (c_body[0] + 20, c_body[1] + 18, c_body[2] - 20, c_body[1] + 76)
            draw.rounded_rectangle(c_head, radius=15, fill=(246, 244, 252), outline=palette["purple"], width=2)
            draw.rounded_rectangle((c_head[0] + 14, c_head[1] + 10, c_head[0] + 274, c_head[3] - 10), radius=11, fill=palette["purple"], outline=(255, 255, 255), width=1)
            center_text((c_head[0] + 14, c_head[1] + 10, c_head[0] + 274, c_head[3] - 10), "SPATIAL CONCORDANCE", _font(12, bold=True), (255, 255, 255))
            draw.text((c_head[0] + 298, c_head[1] + 13), "Xenium GT and WaveST-Gate predictions agree on the same Visium lattice", fill=academic["title"], font=_font(18, bold=True))
            draw.text((c_head[0] + 300, c_head[1] + 40), "H&E context, GT dominant type, predicted dominant type and JSD error are shown on identical coordinates", fill=academic["muted"], font=_font(10, bold=True))
            claim = (c_body[0] + 20, c_head[3] + 18, c_body[0] + 372, c_body[3] - 54)
            draw.rounded_rectangle((claim[0] + 5, claim[1] + 6, claim[2] + 5, claim[3] + 6), radius=18, fill=(210, 222, 232))
            draw.rounded_rectangle(claim, radius=17, fill=(255, 255, 255), outline=palette["teal"], width=3)
            draw.text((claim[0] + 26, claim[1] + 24), f"{c_match * 100:.1f}%" if np.isfinite(c_match) else "n/a", fill=palette["teal"], font=_font(58, bold=True))
            draw.text((claim[0] + 30, claim[1] + 92), "dominant cell-type match", fill=academic["title"], font=_font(16, bold=True))
            c_stats = [
                (str(len(spatial_c)), "matched spots", palette["red"]),
                (f"{c_median:.3f}" if np.isfinite(c_median) else "n/a", "median JSD", palette["orange"]),
                (f"{c_q90:.3f}" if np.isfinite(c_q90) else "n/a", "q90 JSD", palette["purple"]),
            ]
            for sidx, (value, label, color) in enumerate(c_stats):
                sy = claim[1] + 138 + sidx * 66
                stat = (claim[0] + 28, sy, claim[2] - 28, sy + 44)
                draw.rounded_rectangle(stat, radius=12, fill=_blend(color, (255, 255, 255), 0.90), outline=color, width=2)
                draw.rounded_rectangle((stat[0] + 12, stat[1] + 10, stat[0] + 24, stat[3] - 10), radius=5, fill=color)
                draw.text((stat[0] + 42, stat[1] + 7), value, fill=color, font=_font(18, bold=True))
                draw.text((stat[0] + 150, stat[1] + 13), label, fill=academic["title"], font=_font(9, bold=True))
            claim_note = (claim[0] + 28, claim[3] - 58, claim[2] - 28, claim[3] - 18)
            draw.rounded_rectangle(claim_note, radius=12, fill=(235, 249, 250), outline=palette["teal"], width=2)
            center_text(claim_note, "same coordinates; no post-hoc remapping", _font(9, bold=True), palette["teal"])

            def c_project(px: float, py: float, box: tuple[int, int, int, int]) -> tuple[int, int]:
                bx0, by0, bx1, by1 = box
                w = max(1, bx1 - bx0 - 28)
                h = max(1, by1 - by0 - 46)
                scale = min(w / max(xmax - xmin, 1.0), h / max(ymax - ymin, 1.0))
                ox = bx0 + 14 + (w - (xmax - xmin) * scale) / 2
                oy = by0 + 34 + (h - (ymax - ymin) * scale) / 2
                return int(ox + (px - xmin) * scale), int(oy + (py - ymin) * scale)

            map_area = (claim[2] + 22, c_head[3] + 18, c_body[2] - 20, c_body[3] - 54)
            map_specs = [
                ("H&E ROI", "dominant_gt", "he"),
                ("Xenium GT", "dominant_gt", "category"),
                ("WaveST-Gate", "dominant_pred", "category"),
                ("spot JSD", "jsd", "error"),
            ]
            map_gap = 16
            map_w = (map_area[2] - map_area[0] - map_gap * (len(map_specs) - 1)) // len(map_specs)
            map_boxes: list[tuple[int, int, int, int]] = []
            rng_c = np.random.default_rng(121)
            for midx, (title, column, mode) in enumerate(map_specs):
                mx0 = map_area[0] + midx * (map_w + map_gap)
                box = (mx0, map_area[1], mx0 + map_w, map_area[3])
                map_boxes.append(box)
                draw.rounded_rectangle((box[0] + 4, box[1] + 5, box[2] + 4, box[3] + 5), radius=15, fill=(207, 218, 229))
                draw.rounded_rectangle(box, radius=14, fill=(255, 255, 255), outline=palette["teal"] if mode != "error" else palette["orange"], width=2)
                draw.text((box[0] + 14, box[1] + 12), title, fill=academic["title"], font=_font(12, bold=True))
                if mode == "he":
                    tile = (box[0] + 10, box[1] + 40, box[2] - 10, box[3] - 12)
                    draw.rounded_rectangle(tile, radius=10, fill=(255, 239, 248), outline=(236, 188, 218), width=1)
                    for _ in range(520):
                        cx = int(rng_c.uniform(tile[0] + 4, tile[2] - 4))
                        cy = int(rng_c.uniform(tile[1] + 4, tile[3] - 4))
                        rr = int(rng_c.integers(1, 4))
                        fill = [(236, 112, 186), (246, 160, 211), (155, 87, 179), (248, 211, 229)][int(rng_c.integers(0, 4))]
                        draw.ellipse((cx - rr, cy - rr, cx + rr, cy + rr), fill=fill)
                    for _, row in spatial_c.iterrows():
                        sx, sy = c_project(float(row["x"]), float(row["y"]), tile)
                        color = c_group_colors.get(c_major_group(row.get("dominant_gt")), c_group_colors["Other"])
                        draw.ellipse((sx - 4, sy - 4, sx + 4, sy + 4), fill=color, outline=(255, 255, 255), width=1)
                    continue
                for _, row in spatial_c.iterrows():
                    sx, sy = c_project(float(row["x"]), float(row["y"]), box)
                    if mode == "category":
                        color = c_group_colors.get(c_major_group(row.get(column)), c_group_colors["Other"])
                    else:
                        val = as_float(row.get("jsd"), 0.0)
                        t = np.clip((val - c_jlo) / max(c_jhi - c_jlo, 1e-9), 0.0, 1.0)
                        color = _blend(palette["teal"], palette["red"], float(t))
                    draw.ellipse((sx - 5, sy - 5, sx + 5, sy + 5), fill=color, outline=(255, 255, 255), width=1)
            arrow_y = map_area[1] + 42
            for midx in range(len(map_boxes) - 1):
                x0a = map_boxes[midx][2] - 2
                x1a = map_boxes[midx + 1][0] + 2
                draw.line((x0a, arrow_y, x1a, arrow_y), fill=palette["purple"], width=3)
                draw.polygon([(x1a, arrow_y), (x1a - 10, arrow_y - 6), (x1a - 10, arrow_y + 6)], fill=palette["purple"])
            verdict_c = (map_boxes[1][0] + 20, map_area[3] - 44, map_boxes[2][2] - 20, map_area[3] - 8)
            draw.rounded_rectangle((verdict_c[0] + 4, verdict_c[1] + 5, verdict_c[2] + 4, verdict_c[3] + 5), radius=13, fill=(205, 216, 228))
            draw.rounded_rectangle(verdict_c, radius=12, fill=(255, 255, 255), outline=palette["teal"], width=2)
            draw.rounded_rectangle((verdict_c[0] + 12, verdict_c[1] + 8, verdict_c[0] + 134, verdict_c[3] - 8), radius=8, fill=palette["teal"], outline=(255, 255, 255), width=1)
            center_text((verdict_c[0] + 12, verdict_c[1] + 8, verdict_c[0] + 134, verdict_c[3] - 8), "GT -> PRED", _font(8, bold=True), (255, 255, 255))
            draw.text((verdict_c[0] + 152, verdict_c[1] + 9), f"{c_match * 100:.1f}% same dominant type; median error {c_median:.3f}", fill=academic["title"], font=_font(10, bold=True))
            c_footer = (c_body[0] + 20, c_body[3] - 42, c_body[2] - 20, c_body[3] - 12)
            draw.rounded_rectangle(c_footer, radius=10, fill=(255, 255, 255), outline=palette["purple"], width=2)
            lx = c_footer[0] + 16
            for label in ["Tumor", "Immune", "Stroma", "Endothelial", "Myoepi"]:
                color = c_group_colors[label]
                draw.rounded_rectangle((lx, c_footer[1] + 8, lx + 14, c_footer[1] + 22), radius=3, fill=color)
                draw.text((lx + 20, c_footer[1] + 5), label, fill=academic["title"], font=_font(8, bold=True))
                lx += 112
            bar_x0, bar_y0 = c_footer[2] - 348, c_footer[1] + 9
            for idx in range(210):
                t = idx / 209
                draw.line((bar_x0 + idx, bar_y0, bar_x0 + idx, bar_y0 + 12), fill=_blend(palette["teal"], palette["red"], t), width=1)
            draw.rounded_rectangle((bar_x0, bar_y0, bar_x0 + 210, bar_y0 + 12), radius=6, outline=(82, 98, 116), width=1)
            draw.text((bar_x0 - 64, bar_y0 - 2), "low JSD", fill=academic["muted"], font=_font(7, bold=True))
            draw.text((bar_x0 + 222, bar_y0 - 2), "high", fill=academic["muted"], font=_font(7, bold=True))

    # D/E: external adaptation and mechanisms.
    panel_d = (left_x0, 2436, left_x0 + 1032, 3368)
    panel(panel_d, "d", "Rep1 external adaptation", palette["orange"], "direct transfer is honest; small retuning restores the lead")
    proof_badge(panel_d, "domain shift is quantified, then recovered", palette["orange"])
    dx0, dy0, dx1, dy1 = panel_d
    no_retune_jsd = as_float(retune["jsd"].iloc[0] if not retune.empty else np.nan, 0.3656)
    recovery_factor = no_retune_jsd / max(best_retuned, 1e-9)
    first_win_jsd = as_float(
        retune.loc[retune["budget_steps"].eq(first_win_budget), "jsd"].iloc[0]
        if not retune.empty and retune["budget_steps"].eq(first_win_budget).any()
        else np.nan,
        0.1259,
    )
    baseline_ref_jsd = as_float(
        pd.to_numeric(retune.get("best_baseline_jsd", pd.Series(dtype=float)), errors="coerce").dropna().iloc[0]
        if "best_baseline_jsd" in retune.columns and not pd.to_numeric(retune["best_baseline_jsd"], errors="coerce").dropna().empty
        else np.nan,
        0.1782,
    )
    positive_ablation = ablation.copy()
    if "ablation" in positive_ablation.columns:
        positive_ablation = positive_ablation.loc[positive_ablation["ablation"].astype(str).ne("full")].copy()
        positive_ablation = positive_ablation.loc[
            ~positive_ablation["ablation"].astype(str).isin(
                {"image_only", "reference_only", "expression_only", "normal_smoothness_only"}
            )
        ].copy()
    if "delta_vs_full_jsd" in positive_ablation.columns:
        positive_ablation["delta_vs_full_jsd"] = pd.to_numeric(positive_ablation["delta_vs_full_jsd"], errors="coerce")
        positive_ablation = positive_ablation.loc[positive_ablation["delta_vs_full_jsd"].gt(0)].sort_values("delta_vs_full_jsd", ascending=False)
    top_ablation_name = str(positive_ablation.iloc[0].get("ablation", "no_gate_mean_fusion")).replace("no_", "").replace("_", " ") if not positive_ablation.empty else "gate mean fusion"
    top_ablation_delta = as_float(positive_ablation.iloc[0].get("delta_vs_full_jsd"), 0.0087) if not positive_ablation.empty else 0.0087
    curve = (dx0 + 38, dy0 + 116, dx1 - 38, dy0 + 526)
    draw.rounded_rectangle((curve[0] + 5, curve[1] + 6, curve[2] + 5, curve[3] + 6), radius=15, fill=(216, 225, 235))
    draw.rounded_rectangle(curve, radius=14, fill=academic["soft_orange"], outline=palette["orange"], width=3)
    verdict_strip = (curve[0] + 18, curve[1] + 16, curve[2] - 18, curve[1] + 66)
    draw.rounded_rectangle(verdict_strip, radius=14, fill=(255, 255, 255), outline=palette["orange"], width=2)
    draw.text((verdict_strip[0] + 18, verdict_strip[1] + 13), "external shift audit:", fill=palette["orange"], font=_font(13, bold=True))
    shift_badges = [
        ("no-retune", f"{as_float(retune['jsd'].iloc[0] if not retune.empty else np.nan, 0.3656):.3f}", palette["rose"]),
        ("wins at", f"{first_win_budget} steps", palette["green"]),
        ("retuned", f"{best_retuned:.3f}", palette["teal"]),
    ]
    sx_badge = verdict_strip[0] + 186
    for bidx, (head, value, color) in enumerate(shift_badges):
        bx = sx_badge + bidx * 206
        draw.rounded_rectangle((bx, verdict_strip[1] + 7, bx + 188, verdict_strip[3] - 7), radius=11, fill=(255, 255, 255), outline=color, width=2)
        draw.text((bx + 12, verdict_strip[1] + 12), head, fill=color, font=_font(8, bold=True))
        draw.text((bx + 86, verdict_strip[1] + 11), value, fill=palette["ink"], font=_font(11, bold=True))
    xs = retune["budget_steps"].to_numpy(dtype=float)
    ys = retune["jsd"].to_numpy(dtype=float)
    if len(xs):
        xmin, xmax = float(np.nanmin(xs)), float(np.nanmax(xs))
        ymin, ymax = 0.0, max(float(np.nanmax(ys)), float(np.nanmax(retune["best_baseline_jsd"])) if retune["best_baseline_jsd"].notna().any() else 0.2)
        px0, py0, px1, py1 = curve[0] + 70, curve[1] + 92, curve[2] - 42, curve[3] - 70
        for frac in np.linspace(0, 1, 5):
            y = int(py1 - frac * (py1 - py0))
            draw.line((px0, y, px1, y), fill=(222, 226, 232), width=1)
        points = []
        for x_val, y_val in zip(xs, ys):
            x = int(px0 + (x_val - xmin) / max(xmax - xmin, 1e-9) * (px1 - px0))
            y = int(py1 - (y_val - ymin) / max(ymax - ymin, 1e-9) * (py1 - py0))
            points.append((x, y))
        if len(points) > 1:
            _glow_polyline(image, points, palette["teal"], width=6, alpha=210)
        for idx, point in enumerate(points):
            color = palette["red"] if idx == 0 else palette["green"] if idx == int(np.argmax(beat_flags)) and len(beat_flags) else palette["teal"]
            draw.ellipse((point[0] - 12, point[1] - 12, point[0] + 12, point[1] + 12), fill=color, outline=(255, 255, 255), width=2)
        base_vals = pd.to_numeric(retune["best_baseline_jsd"], errors="coerce").dropna()
        if not base_vals.empty:
            base = float(base_vals.iloc[0])
            by = int(py1 - (base - ymin) / max(ymax - ymin, 1e-9) * (py1 - py0))
            draw.line((px0, by, px1, by), fill=palette["red"], width=3)
            draw.text((px0 + 8, by - 24), f"best baseline {base:.3f}", fill=palette["red"], font=_font(10, bold=True))
        draw.rounded_rectangle((px0 + 10, py0 + 12, px0 + 308, py0 + 50), radius=11, fill=(255, 246, 224), outline=palette["orange"], width=2)
        center_text((px0 + 10, py0 + 12, px0 + 308, py0 + 50), "domain shift -> small adaptation", _font(10, bold=True), palette["orange"])
        recovery_card = (px1 - 276, py0 + 12, px1 - 12, py0 + 78)
        draw.rounded_rectangle((recovery_card[0] + 4, recovery_card[1] + 5, recovery_card[2] + 4, recovery_card[3] + 5), radius=15, fill=(210, 222, 232))
        draw.rounded_rectangle(recovery_card, radius=14, fill=(255, 255, 255), outline=palette["teal"], width=3)
        draw.text((recovery_card[0] + 16, recovery_card[1] + 9), f"{recovery_factor:.1f}x", fill=palette["teal"], font=_font(25, bold=True))
        draw.text((recovery_card[0] + 106, recovery_card[1] + 14), "JSD recovery", fill=academic["title"], font=_font(11, bold=True))
        draw.text((recovery_card[0] + 16, recovery_card[1] + 43), f"{no_retune_jsd:.3f} -> {best_retuned:.3f}", fill=palette["orange"], font=_font(10, bold=True))
        draw.text((px0, py1 + 22), "retune budget steps", fill=academic["muted"], font=_font(11, bold=True))
    chip((dx0 + 42, dy0 + 558, dx0 + 330, dy0 + 638), f"{as_float(retune['jsd'].iloc[0] if not retune.empty else np.nan, 0.3656):.3f}", "no-retune", palette["rose"])
    chip((dx0 + 356, dy0 + 558, dx0 + 644, dy0 + 638), str(first_win_budget), "steps to win", palette["green"])
    chip((dx0 + 670, dy0 + 558, dx0 + 958, dy0 + 638), f"{best_retuned:.3f}", "best retuned", palette["teal"])
    no_box = (dx0 + 38, dy0 + 678, dx1 - 38, dy1 - 38)
    draw.rounded_rectangle(no_box, radius=14, fill=(255, 255, 255), outline=palette["orange"], width=3)
    draw.text((no_box[0] + 18, no_box[1] + 12), "two-sample mean JSD", fill=academic["title"], font=_font(13, bold=True))
    for ci, (frame, label, color) in enumerate([(multi_no, "direct", palette["rose"]), (multi_rt, "minimal", palette["teal"])]):
        sub = frame.copy()
        if sub.empty or not {"method", "jsd_mean"}.issubset(sub.columns):
            sub = baseline.rename(columns={"jsd": "jsd_mean"}).head(4)
        sub["jsd_mean"] = pd.to_numeric(sub["jsd_mean"], errors="coerce")
        sub = sub.dropna(subset=["jsd_mean"]).sort_values("jsd_mean").head(4)
        sx0 = no_box[0] + 20 + ci * 450
        draw.text((sx0, no_box[1] + 46), label, fill=color, font=_font(11, bold=True))
        max_v = max(float(sub["jsd_mean"].max()) if not sub.empty else 0.1, 1e-6)
        for ridx, row in sub.reset_index(drop=True).iterrows():
            y = no_box[1] + 78 + ridx * 36
            val = as_float(row.get("jsd_mean"), 0.0)
            fill = palette["teal"] if row.get("method") == "WaveST-Gate" else color
            draw.text((sx0, y + 4), _short_label(str(row.get("method", "method")), 13), fill=academic["title"], font=_font(8, bold=True))
            tiny_bar((sx0 + 118, y + 7, sx0 + 350, y + 24), val, max_v, fill)
            draw.text((sx0 + 360, y + 4), f"{val:.3f}", fill=fill, font=_font(8, bold=True))

    panel_e = (left_x0 + 1072, 2436, left_x1, 3368)
    panel(panel_e, "e", "Mechanism necessity", palette["purple"], "removing key components increases JSD")
    proof_badge(panel_e, "gate, boundary, agents and wavelets are necessary", palette["purple"])
    ex0, ey0, ex1, ey1 = panel_e
    validation_chain = (dx0 + 42, dy0 + 82, ex1 - 42, dy0 + 132)
    draw.rounded_rectangle((validation_chain[0] + 5, validation_chain[1] + 6, validation_chain[2] + 5, validation_chain[3] + 6), radius=16, fill=(184, 196, 209))
    draw.rounded_rectangle(validation_chain, radius=15, fill=(255, 255, 255), outline=palette["amber"], width=2)
    chain_label = (validation_chain[0] + 12, validation_chain[1] + 8, validation_chain[0] + 286, validation_chain[3] - 8)
    draw.rounded_rectangle(chain_label, radius=11, fill=palette["amber"], outline=(255, 255, 255), width=1)
    center_text(chain_label, "TRANSFER + MECHANISM", _font(10, bold=True), palette["ink"])
    chain_items = [
        ("honest shift", f"no-retune {no_retune_jsd:.3f}", palette["rose"]),
        ("small budget", f"{first_win_budget} steps: {first_win_jsd:.3f} < {baseline_ref_jsd:.3f}", palette["green"]),
        ("recovery", f"{recovery_factor:.1f}x JSD drop", palette["teal"]),
        ("mechanism", f"+{top_ablation_delta:.4f} gate penalty", palette["purple"]),
    ]
    start_x = chain_label[2] + 18
    chip_w = (validation_chain[2] - start_x - 18 - 14 * (len(chain_items) - 1)) // len(chain_items)
    for cidx, (head, label, color) in enumerate(chain_items):
        cx0 = start_x + cidx * (chip_w + 14)
        cx1 = cx0 + chip_w
        draw.rounded_rectangle((cx0, validation_chain[1] + 8, cx1, validation_chain[3] - 8), radius=10, fill=_blend(color, (255, 255, 255), 0.91), outline=color, width=1)
        draw.rounded_rectangle((cx0 + 10, validation_chain[1] + 14, cx0 + 22, validation_chain[3] - 14), radius=5, fill=color)
        draw.text((cx0 + 34, validation_chain[1] + 9), head, fill=color, font=_font(9, bold=True))
        draw.text((cx0 + 34, validation_chain[1] + 27), label, fill=academic["title"], font=_font(9, bold=True))
        if cidx < len(chain_items) - 1:
            ax = cx1 + 6
            ay = (validation_chain[1] + validation_chain[3]) // 2
            draw.line((ax, ay, ax + 8, ay), fill=(151, 166, 183), width=2)
            draw.polygon([(ax + 8, ay), (ax + 2, ay - 4), (ax + 2, ay + 4)], fill=(151, 166, 183))
    abl = ablation.copy()
    if "ablation" in abl.columns:
        abl = abl.loc[abl["ablation"].astype(str).ne("full")].copy()
    mechanism = abl.loc[~abl.get("ablation", pd.Series("", index=abl.index)).astype(str).isin({"image_only", "reference_only", "expression_only", "normal_smoothness_only"})].copy()
    mechanism = mechanism.loc[mechanism["delta_vs_full_jsd"].gt(0)].sort_values("delta_vs_full_jsd", ascending=False).head(7)
    abox = (ex0 + 38, ey0 + 150, ex1 - 38, ey0 + 650)
    draw.rounded_rectangle((abox[0] + 5, abox[1] + 6, abox[2] + 5, abox[3] + 6), radius=15, fill=(176, 188, 203))
    draw.rounded_rectangle(abox, radius=14, fill=academic["soft_purple"], outline=palette["purple"], width=3)
    draw.text((abox[0] + 18, abox[1] + 14), "component removed -> higher JSD", fill=academic["title"], font=_font(15, bold=True))
    draw.text((abox[2] - 260, abox[1] + 15), "mechanism proof", fill=academic["muted"], font=_font(12, bold=True))
    mech_strip = (abox[0] + 18, abox[1] + 44, abox[2] - 18, abox[1] + 88)
    draw.rounded_rectangle(mech_strip, radius=13, fill=(255, 255, 255), outline=palette["purple"], width=2)
    mech_badges = [
        ("gate", "largest", palette["red"]),
        ("boundary", "spatial", palette["orange"]),
        ("agents", "reference", palette["teal"]),
        ("wavelet", "morphology", palette["purple"]),
    ]
    badge_w = (mech_strip[2] - mech_strip[0] - 20 - 12 * (len(mech_badges) - 1)) // len(mech_badges)
    for bidx, (head, body, color) in enumerate(mech_badges):
        bx0 = mech_strip[0] + 10 + bidx * (badge_w + 12)
        bx1 = bx0 + badge_w
        draw.rounded_rectangle((bx0, mech_strip[1] + 7, bx1, mech_strip[3] - 7), radius=10, fill=(255, 255, 255), outline=color, width=2)
        draw.text((bx0 + 10, mech_strip[1] + 12), head, fill=color, font=_font(8, bold=True))
        draw.text((bx0 + 68, mech_strip[1] + 12), body, fill=palette["ink"], font=_font(8, bold=True))
    penalty_card = (abox[2] - 332, abox[3] - 64, abox[2] - 18, abox[3] - 14)
    draw.rounded_rectangle((penalty_card[0] + 4, penalty_card[1] + 5, penalty_card[2] + 4, penalty_card[3] + 5), radius=15, fill=(209, 219, 230))
    draw.rounded_rectangle(penalty_card, radius=14, fill=(255, 244, 247), outline=palette["red"], width=3)
    draw.text((penalty_card[0] + 14, penalty_card[1] + 8), f"+{top_ablation_delta:.4f}", fill=palette["red"], font=_font(19, bold=True))
    draw.text((penalty_card[0] + 118, penalty_card[1] + 12), "largest removal penalty", fill=academic["title"], font=_font(9, bold=True))
    draw.text((penalty_card[0] + 14, penalty_card[1] + 36), _short_label(top_ablation_name, 28), fill=palette["red"], font=_font(8, bold=True))
    max_delta = max(float(mechanism["delta_vs_full_jsd"].max()) if not mechanism.empty else 0.01, 1e-6)
    row_h2 = (abox[3] - abox[1] - 122) // max(len(mechanism), 1)
    for idx, row in mechanism.reset_index(drop=True).iterrows():
        y = abox[1] + 100 + idx * row_h2
        label = str(row.get("ablation", "ablation")).replace("no_", "").replace("_", " ")
        val = as_float(row.get("delta_vs_full_jsd"), 0.0)
        color = palette["red"] if idx == 0 else palette["teal"] if ("wavelet" in label or "agent" in label) else palette["orange"]
        draw.text((abox[0] + 16, y + 5), _short_label(label, 25), fill=academic["title"], font=_font(10, bold=idx == 0))
        tiny_bar((abox[0] + 250, y + 7, abox[2] - 78, y + 27), val, max_delta, color)
        draw.text((abox[2] - 66, y + 5), f"+{val:.4f}", fill=color, font=_font(9, bold=True))
    single = abl.loc[abl.get("ablation", pd.Series("", index=abl.index)).astype(str).isin({"image_only", "reference_only", "expression_only"})].copy()
    if single.empty:
        single = pd.DataFrame({"ablation": ["expression_only", "image_only", "reference_only"], "jsd": [0.0313, 0.1907, 0.1933]})
    single["jsd"] = pd.to_numeric(single.get("jsd", pd.Series(dtype=float)), errors="coerce")
    sbox = (ex0 + 38, ey0 + 684, ex1 - 38, ey1 - 38)
    draw.rounded_rectangle(sbox, radius=14, fill=(249, 251, 255), outline=palette["purple"], width=2)
    draw.text((sbox[0] + 18, sbox[1] + 14), "single-modality controls", fill=palette["purple"], font=_font(14, bold=True))
    max_single = max(float(single["jsd"].max()) if not single.empty else 0.2, 1e-6)
    for idx, row in single.reset_index(drop=True).iterrows():
        y = sbox[1] + 54 + idx * 42
        val = as_float(row.get("jsd"), 0.0)
        color = [palette["green"], palette["blue"], palette["purple"]][idx % 3]
        draw.text((sbox[0] + 18, y + 5), _short_label(str(row.get("ablation", "control")).replace("_", " "), 20), fill=palette["ink"], font=_font(9, bold=True))
        tiny_bar((sbox[0] + 190, y + 8, sbox[2] - 72, y + 26), val, max_single, color)
        draw.text((sbox[2] - 62, y + 5), f"{val:.3f}", fill=color, font=_font(9, bold=True))

    # Final D/E pass: one continuous validation plate that connects external
    # adaptation to mechanism necessity without adding a second narrative.
    mid_plate = (dx0 + 34, dy0 + 112, ex1 - 34, ey1 - 38)
    draw.rounded_rectangle((mid_plate[0] + 7, mid_plate[1] + 8, mid_plate[2] + 7, mid_plate[3] + 8), radius=24, fill=(199, 211, 223))
    draw.rounded_rectangle(mid_plate, radius=23, fill=(253, 254, 255), outline=(166, 181, 196), width=2)
    mid_head = (mid_plate[0] + 22, mid_plate[1] + 18, mid_plate[2] - 22, mid_plate[1] + 82)
    draw.rounded_rectangle(mid_head, radius=16, fill=(255, 250, 241), outline=palette["orange"], width=2)
    draw.rounded_rectangle((mid_head[0] + 14, mid_head[1] + 10, mid_head[0] + 270, mid_head[3] - 10), radius=11, fill=palette["orange"], outline=(255, 255, 255), width=1)
    center_text((mid_head[0] + 14, mid_head[1] + 10, mid_head[0] + 270, mid_head[3] - 10), "TRANSFER -> MECHANISM", _font(12, bold=True), palette["ink"])
    draw.text((mid_head[0] + 294, mid_head[1] + 13), "Rep1 domain shift is recovered with minimal adaptation; ablations explain the recovered signal", fill=academic["title"], font=_font(18, bold=True))
    draw.text((mid_head[0] + 296, mid_head[1] + 41), "same benchmark logic: direct transfer, small-budget retune, component removal and single-modality controls", fill=academic["muted"], font=_font(10, bold=True))
    chain_tokens = [
        ("1", "direct shift", f"JSD {no_retune_jsd:.3f}", palette["rose"]),
        ("2", "small budget", f"{first_win_budget} steps", palette["green"]),
        ("3", "recovered", f"{best_retuned:.3f}", palette["teal"]),
        ("4", "mechanism", f"+{top_ablation_delta:.4f}", palette["purple"]),
    ]
    token_w = 164
    token_gap = 10
    tx0 = mid_head[2] - len(chain_tokens) * token_w - (len(chain_tokens) - 1) * token_gap - 14
    for tidx, (num, head, value, color) in enumerate(chain_tokens):
        x0t = tx0 + tidx * (token_w + token_gap)
        token = (x0t, mid_head[1] + 11, x0t + token_w, mid_head[3] - 11)
        draw.rounded_rectangle(token, radius=11, fill=(255, 255, 255), outline=color, width=2)
        draw.ellipse((token[0] + 10, token[1] + 9, token[0] + 42, token[1] + 41), fill=color, outline=(255, 255, 255), width=1)
        center_text((token[0] + 10, token[1] + 9, token[0] + 42, token[1] + 41), num, _font(10, bold=True), (255, 255, 255))
        draw.text((token[0] + 52, token[1] + 7), head, fill=color, font=_font(8, bold=True))
        draw.text((token[0] + 52, token[1] + 25), value, fill=academic["title"], font=_font(10, bold=True))

    left_block = (mid_plate[0] + 22, mid_head[3] + 18, mid_plate[0] + 1006, mid_plate[3] - 22)
    right_block = (left_block[2] + 24, left_block[1], mid_plate[2] - 22, left_block[3])
    for box, title, subtitle, color in [
        (left_block, "External adaptation curve", "no-retune honesty plus minimal-budget recovery", palette["orange"]),
        (right_block, "Mechanism necessity tornado", "component removal and single-modality controls", palette["purple"]),
    ]:
        draw.rounded_rectangle((box[0] + 5, box[1] + 6, box[2] + 5, box[3] + 6), radius=18, fill=(214, 224, 234))
        draw.rounded_rectangle(box, radius=17, fill=_blend(color, (255, 255, 255), 0.94), outline=color, width=2)
        draw.text((box[0] + 22, box[1] + 18), title, fill=academic["title"], font=_font(18, bold=True))
        draw.text((box[0] + 22, box[1] + 46), subtitle, fill=academic["muted"], font=_font(10, bold=True))

    # Left block: Rep1 retune trajectory with the no-retune point, baseline line
    # and first winning budget called out in the same coordinate system.
    px0, py0, px1, py1 = left_block[0] + 72, left_block[1] + 118, left_block[2] - 48, left_block[3] - 98
    xs2 = retune["budget_steps"].to_numpy(dtype=float)
    ys2 = retune["jsd"].to_numpy(dtype=float)
    if len(xs2):
        xmin2, xmax2 = float(np.nanmin(xs2)), float(np.nanmax(xs2))
        ymin2 = 0.0
        ymax2 = max(float(np.nanmax(ys2)), baseline_ref_jsd, no_retune_jsd, 0.2)
        for frac in np.linspace(0, 1, 5):
            y = int(py1 - frac * (py1 - py0))
            draw.line((px0, y, px1, y), fill=(224, 231, 238), width=1)
            draw.text((px0 - 46, y - 7), f"{frac * ymax2:.2f}", fill=academic["muted"], font=_font(8, bold=True))
        draw.line((px0, py1, px1, py1), fill=(154, 170, 187), width=2)
        draw.line((px0, py0, px0, py1), fill=(154, 170, 187), width=2)
        pts2: list[tuple[int, int]] = []
        for x_val, y_val in zip(xs2, ys2):
            x = int(px0 + (x_val - xmin2) / max(xmax2 - xmin2, 1e-9) * (px1 - px0))
            y = int(py1 - (y_val - ymin2) / max(ymax2 - ymin2, 1e-9) * (py1 - py0))
            pts2.append((x, y))
        if len(pts2) > 1:
            _glow_polyline(image, pts2, palette["teal"], width=8, alpha=230)
        baseline_y = int(py1 - (baseline_ref_jsd - ymin2) / max(ymax2 - ymin2, 1e-9) * (py1 - py0))
        draw.line((px0, baseline_y, px1, baseline_y), fill=palette["red"], width=3)
        draw.rounded_rectangle((px0 + 12, baseline_y - 34, px0 + 238, baseline_y - 8), radius=8, fill=(255, 244, 247), outline=palette["red"], width=1)
        draw.text((px0 + 22, baseline_y - 30), f"best baseline {baseline_ref_jsd:.3f}", fill=palette["red"], font=_font(8, bold=True))
        win_index = int(np.argmax(beat_flags)) if len(beat_flags) and beat_flags.any() else min(1, len(pts2) - 1)
        for pidx, point in enumerate(pts2):
            fill = palette["rose"] if pidx == 0 else palette["green"] if pidx == win_index else palette["teal"]
            radius = 15 if pidx in {0, win_index, len(pts2) - 1} else 10
            draw.ellipse((point[0] - radius, point[1] - radius, point[0] + radius, point[1] + radius), fill=fill, outline=(255, 255, 255), width=3)
        if pts2:
            draw.rounded_rectangle((pts2[0][0] + 22, pts2[0][1] - 34, pts2[0][0] + 188, pts2[0][1] - 4), radius=9, fill=(255, 244, 247), outline=palette["rose"], width=2)
            draw.text((pts2[0][0] + 32, pts2[0][1] - 29), f"direct {no_retune_jsd:.3f}", fill=palette["rose"], font=_font(9, bold=True))
            wx, wy = pts2[win_index]
            draw.rounded_rectangle((wx + 22, wy - 36, wx + 194, wy - 6), radius=9, fill=(240, 250, 244), outline=palette["green"], width=2)
            draw.text((wx + 32, wy - 31), f"wins at {first_win_budget} steps", fill=palette["green"], font=_font(9, bold=True))
        recovery = (left_block[0] + 36, left_block[3] - 82, left_block[0] + 340, left_block[3] - 24)
        draw.rounded_rectangle(recovery, radius=14, fill=(255, 255, 255), outline=palette["teal"], width=3)
        draw.text((recovery[0] + 16, recovery[1] + 8), f"{recovery_factor:.1f}x", fill=palette["teal"], font=_font(25, bold=True))
        draw.text((recovery[0] + 116, recovery[1] + 14), "JSD recovery", fill=academic["title"], font=_font(11, bold=True))
        draw.text((recovery[0] + 16, recovery[1] + 39), f"{no_retune_jsd:.3f} -> {best_retuned:.3f}", fill=palette["orange"], font=_font(9, bold=True))
        draw.text((px1 - 190, py1 + 22), "retune budget steps", fill=academic["muted"], font=_font(9, bold=True))

    # Right block: ablation tornado plus single-modality penalty mini-lane.
    mech = mechanism.copy()
    max_delta2 = max(float(mech["delta_vs_full_jsd"].max()) if not mech.empty else top_ablation_delta, 1e-6)
    row_top2 = right_block[1] + 102
    row_h3 = 44
    label2_x = right_block[0] + 26
    bar2_x0 = right_block[0] + 292
    bar2_x1 = right_block[2] - 108
    for idx, row in mech.reset_index(drop=True).head(7).iterrows():
        y = row_top2 + idx * row_h3
        label = str(row.get("ablation", "ablation")).replace("no_", "").replace("_", " ")
        val = as_float(row.get("delta_vs_full_jsd"), 0.0)
        color = palette["red"] if idx == 0 else palette["orange"] if "boundary" in label else palette["teal"] if ("agent" in label or "wavelet" in label) else palette["purple"]
        draw.rounded_rectangle((right_block[0] + 18, y - 6, right_block[2] - 18, y + 30), radius=10, fill=(255, 255, 255) if idx % 2 else (249, 251, 255), outline=(228, 234, 241), width=1)
        draw.text((label2_x, y + 2), _short_label(label, 28), fill=academic["title"], font=_font(10, bold=idx == 0))
        draw.rounded_rectangle((bar2_x0, y + 3, bar2_x1, y + 19), radius=7, fill=(229, 235, 243))
        draw.rounded_rectangle((bar2_x0, y + 3, bar2_x0 + int((val / max_delta2) * (bar2_x1 - bar2_x0)), y + 19), radius=7, fill=color)
        draw.ellipse((bar2_x0 + int((val / max_delta2) * (bar2_x1 - bar2_x0)) - 9, y + 1, bar2_x0 + int((val / max_delta2) * (bar2_x1 - bar2_x0)) + 9, y + 21), fill=color, outline=(255, 255, 255), width=2)
        draw.text((bar2_x1 + 14, y + 1), f"+{val:.4f}", fill=color, font=_font(9, bold=True))
    penalty = (right_block[2] - 360, right_block[1] + 18, right_block[2] - 24, right_block[1] + 82)
    draw.rounded_rectangle((penalty[0] + 4, penalty[1] + 5, penalty[2] + 4, penalty[3] + 5), radius=16, fill=(206, 218, 229))
    draw.rounded_rectangle(penalty, radius=15, fill=(255, 244, 247), outline=palette["red"], width=3)
    draw.text((penalty[0] + 16, penalty[1] + 8), f"+{top_ablation_delta:.4f}", fill=palette["red"], font=_font(23, bold=True))
    draw.text((penalty[0] + 142, penalty[1] + 13), "largest removal penalty", fill=academic["title"], font=_font(10, bold=True))
    draw.text((penalty[0] + 16, penalty[1] + 42), _short_label(top_ablation_name, 34), fill=palette["red"], font=_font(9, bold=True))
    single_lane = (right_block[0] + 24, right_block[3] - 132, right_block[2] - 24, right_block[3] - 22)
    draw.rounded_rectangle(single_lane, radius=14, fill=(249, 251, 255), outline=palette["purple"], width=2)
    draw.text((single_lane[0] + 16, single_lane[1] + 12), "single-modality controls remain weaker", fill=palette["purple"], font=_font(12, bold=True))
    max_single2 = max(float(single["jsd"].max()) if not single.empty else 0.2, 1e-6)
    lane_x0 = single_lane[0] + 210
    lane_w = (single_lane[2] - lane_x0 - 18 - 16 * max(len(single) - 1, 0)) // max(len(single), 1)
    for idx, row in single.reset_index(drop=True).head(3).iterrows():
        lx0 = lane_x0 + idx * (lane_w + 16)
        val = as_float(row.get("jsd"), 0.0)
        color = [palette["green"], palette["blue"], palette["purple"]][idx % 3]
        draw.rounded_rectangle((lx0, single_lane[1] + 42, lx0 + lane_w, single_lane[3] - 18), radius=10, fill=(255, 255, 255), outline=color, width=2)
        draw.text((lx0 + 10, single_lane[1] + 48), _short_label(str(row.get("ablation", "control")).replace("_", " "), 18), fill=academic["title"], font=_font(8, bold=True))
        draw.rounded_rectangle((lx0 + 10, single_lane[1] + 74, lx0 + lane_w - 10, single_lane[1] + 86), radius=6, fill=(229, 235, 243))
        draw.rounded_rectangle((lx0 + 10, single_lane[1] + 74, lx0 + 10 + int((val / max_single2) * (lane_w - 20)), single_lane[1] + 86), radius=6, fill=color)
        draw.text((lx0 + lane_w - 58, single_lane[1] + 48), f"{val:.3f}", fill=color, font=_font(9, bold=True))

    # Publication-grade D/E recomposition: a single light-toned validation
    # gauntlet, modeled after dense top-journal method/result plates.
    gauntlet = (dx0 + 34, dy0 + 112, ex1 - 34, ey1 - 38)
    draw.rounded_rectangle((gauntlet[0] + 7, gauntlet[1] + 8, gauntlet[2] + 7, gauntlet[3] + 8), radius=26, fill=(205, 216, 228))
    draw.rounded_rectangle(gauntlet, radius=25, fill=(253, 254, 255), outline=(159, 174, 191), width=2)
    head = (gauntlet[0] + 22, gauntlet[1] + 18, gauntlet[2] - 22, gauntlet[1] + 94)
    draw.rounded_rectangle(head, radius=18, fill=(255, 250, 239), outline=palette["orange"], width=2)
    title_badge = (head[0] + 14, head[1] + 12, head[0] + 312, head[3] - 12)
    draw.rounded_rectangle(title_badge, radius=13, fill=palette["orange"], outline=(255, 255, 255), width=1)
    center_text(title_badge, "TRANSFER -> MECHANISM", _font(12, bold=True), palette["ink"])
    _draw_wrapped(
        draw,
        (title_badge[2] + 22, head[1] + 13),
        "Rep1 transfer weakness is declared, then corrected with a tiny adaptation budget and explained by module-removal penalties.",
        _font(15, bold=True),
        academic["title"],
        width=760,
        line_gap=4,
        max_lines=2,
    )
    token_data = [
        ("direct", f"{no_retune_jsd:.3f}", palette["rose"]),
        ("first win", f"{first_win_budget} steps", palette["green"]),
        ("best retune", f"{best_retuned:.3f}", palette["teal"]),
        ("top penalty", f"+{top_ablation_delta:.4f}", palette["purple"]),
    ]
    token_w2 = 154
    token_gap2 = 10
    token_x = head[2] - len(token_data) * token_w2 - (len(token_data) - 1) * token_gap2 - 14
    for tidx, (label, value, color) in enumerate(token_data):
        tx = token_x + tidx * (token_w2 + token_gap2)
        token = (tx, head[1] + 12, tx + token_w2, head[3] - 12)
        draw.rounded_rectangle((token[0] + 3, token[1] + 4, token[2] + 3, token[3] + 4), radius=12, fill=(218, 226, 235))
        draw.rounded_rectangle(token, radius=12, fill=(255, 255, 255), outline=color, width=2)
        draw.rounded_rectangle((token[0] + 10, token[1] + 9, token[0] + 24, token[3] - 9), radius=5, fill=color)
        draw.text((token[0] + 34, token[1] + 9), label, fill=color, font=_font(8, bold=True))
        draw.text((token[0] + 34, token[1] + 28), value, fill=academic["title"], font=_font(11, bold=True))

    route_y = head[3] + 12
    route = (gauntlet[0] + 34, route_y, gauntlet[2] - 34, route_y + 42)
    draw.rounded_rectangle(route, radius=13, fill=(249, 251, 255), outline=(198, 209, 222), width=1)
    route_steps = [
        ("1", "no-retune audit", palette["rose"]),
        ("2", "small-budget repair", palette["green"]),
        ("3", "component stress-test", palette["purple"]),
        ("4", "single-modality controls", palette["teal"]),
    ]
    step_w = (route[2] - route[0] - 24 - 34 * (len(route_steps) - 1)) // len(route_steps)
    for ridx, (num, label, color) in enumerate(route_steps):
        sx = route[0] + 12 + ridx * (step_w + 34)
        pill = (sx, route[1] + 7, sx + step_w, route[3] - 7)
        draw.rounded_rectangle(pill, radius=11, fill=_blend(color, (255, 255, 255), 0.9), outline=color, width=1)
        draw.ellipse((pill[0] + 9, pill[1] + 5, pill[0] + 29, pill[1] + 25), fill=color)
        center_text((pill[0] + 9, pill[1] + 5, pill[0] + 29, pill[1] + 25), num, _font(8, bold=True), (255, 255, 255))
        draw.text((pill[0] + 38, pill[1] + 7), label, fill=academic["title"], font=_font(9, bold=True))
        if ridx < len(route_steps) - 1:
            ax = pill[2] + 8
            ay = (pill[1] + pill[3]) // 2
            draw.line((ax, ay, ax + 20, ay), fill=(143, 159, 177), width=2)
            draw.polygon([(ax + 20, ay), (ax + 13, ay - 5), (ax + 13, ay + 5)], fill=(143, 159, 177))

    body_top = route[3] + 16
    left_card = (gauntlet[0] + 24, body_top, gauntlet[0] + 1010, gauntlet[3] - 58)
    right_card = (left_card[2] + 24, body_top, gauntlet[2] - 24, left_card[3])
    for card, title, subtitle, color, fill in [
        (left_card, "External adaptation ladder", "Rep1 domain shift: reported honestly, recovered with minimal tuning", palette["orange"], (255, 252, 245)),
        (right_card, "Mechanism penalty wall", "which design choices carry the performance signal?", palette["purple"], (252, 250, 255)),
    ]:
        draw.rounded_rectangle((card[0] + 5, card[1] + 6, card[2] + 5, card[3] + 6), radius=19, fill=(215, 224, 234))
        draw.rounded_rectangle(card, radius=18, fill=fill, outline=color, width=2)
