    serr = split3_frame["sd_jsd"].to_numpy(dtype=float)
    sylo = float(np.nanmin(svals - serr)) if len(svals) else 0.0
    syhi = float(np.nanmax(svals + serr)) if len(svals) else 1.0
    sylo = min(sylo, best_jsd * 0.96)
    syhi = max(syhi, best_jsd * 1.12)
    for frac in np.linspace(0, 1, 4):
        y = int(sp[3] - frac * (sp[3] - sp[1]))
