        sd = float(row["sd_jsd"])
        cy = int(sp[3] - (mean - sylo) / max(syhi - sylo, 1e-9) * (sp[3] - sp[1]))
        ylo = int(sp[3] - (mean - sd - sylo) / max(syhi - sylo, 1e-9) * (sp[3] - sp[1]))
        yhi = int(sp[3] - (mean + sd - sylo) / max(syhi - sylo, 1e-9) * (sp[3] - sp[1]))
        draw.line((cx, yhi, cx, ylo), fill=palette["teal"], width=4)
        draw.ellipse((cx - 15, cy - 15, cx + 15, cy + 15), fill=palette["teal"], outline=(255, 255, 255), width=3)
        label = str(row.get("split", ""))[:8]
        center_text((cx - 48, split3[3] - 58, cx + 48, split3[3] - 36), label, _font(9, bold=True), academic["title"])
