    noleak = (split3[2] - 190, split3[1] + 72, split3[2] - 24, split3[1] + 112)
    draw.rounded_rectangle(noleak, radius=11, fill=(255, 255, 255), outline=palette["teal"], width=2)
    center_text(noleak, "no test leakage", _font(9, bold=True), palette["teal"])

    # Q3/Q5: explicit audit checklist.
    audit3 = audit.copy()
    if audit3.empty or not {"check", "status"}.issubset(audit3.columns):
        audit3 = pd.DataFrame({"check": ["split uniqueness", "split disjointness", "GT inventory", "config split guard", "baseline inputs", "label permutation"], "status": ["pass", "pass", "pass", "warn", "pass", "pass"]})
    checklist = audit3.head(7).reset_index(drop=True)
    row_h_check = (checks3[3] - checks3[1] - 104) // max(len(checklist), 1)
    for idx, row in checklist.iterrows():
        y = checks3[1] + 82 + idx * row_h_check
        status = str(row.get("status", "")).lower()
