    draw.text((flag_chip[2] + 26, flagship[1] + 28), "Comprehensive Assessment", fill=academic["title"], font=_font(35, bold=True))
    draw.text((flag_chip[2] + 28, flagship[1] + 76), "13 methods | matched GT | Rep1 transfer | minimal retune | audit", fill=palette["red"], font=_font(15, bold=True))
    right_flag = (flagship[2] - 274, flagship[1] + 26, flagship[2] - 22, flagship[3] - 26)
    draw.rounded_rectangle(right_flag, radius=18, fill=(255, 246, 224), outline=palette["amber"], width=3)
    center_text((right_flag[0], right_flag[1] + 8, right_flag[2], right_flag[1] + 66), f"{fold:.1f}x", _font(38, bold=True), palette["red"])
    center_text((right_flag[0], right_flag[1] + 66, right_flag[2], right_flag[3] - 8), "lower matched JSD", _font(10, bold=True), palette["orange"])
    flag_metrics = [
        (f"{best_jsd:.5f}", "best JSD", palette["teal"]),
        ("485", "GT spots", palette["orange"]),
        ("297", "genes", palette["purple"]),
        ("PASS", "audit", palette["green"]),
    ]
    fm_x0 = flag_chip[2] + 28
    fm_y0 = flagship[1] + 104
    fm_w = (right_flag[0] - fm_x0 - 34 - 12 * (len(flag_metrics) - 1)) // len(flag_metrics)
    for fidx, (value, label, color) in enumerate(flag_metrics):
        mx0 = fm_x0 + fidx * (fm_w + 12)
        metric = (mx0, fm_y0, mx0 + fm_w, flagship[3] - 24)
        draw.rounded_rectangle(metric, radius=12, fill=(255, 255, 255), outline=color, width=2)
        draw.rounded_rectangle((metric[0] + 10, metric[1] + 10, metric[0] + 22, metric[3] - 10), radius=5, fill=color)
        draw.text((metric[0] + 34, metric[1] + 8), value, fill=color, font=_font(14, bold=True))
        draw.text((metric[0] + 34, metric[1] + 31), label, fill=academic["title"], font=_font(8, bold=True))

    # Make the left evidence chain behave like the reference figure's procedure
    # block: one contract, one primary result, one spatial check, one validation
    # deck. The labels sit on panel margins, so they do not hide data marks.
    stage_callouts = [
        (panel_a, "1", "Benchmark contract", "Xenium cells define spot-level GT before comparison", palette["red"]),
        (panel_b, "2", "Primary rank cliff", f"WaveST-Gate is #1 with {fold:.1f}x lower JSD", palette["teal"]),
        (panel_c, "3", "Coordinate evidence", "GT, prediction and error share the same Visium lattice", palette["purple"]),
        (panel_d, "4", "Transfer and mechanism", "domain shift, minimal retune and ablations explain robustness", palette["orange"]),
        (panel_f, "5", "Reviewer controls", "sensitivity, split, permutation and bootstrap close the loop", palette["green"]),
    ]
    for xy, num, title, subtitle, color in stage_callouts:
        x0, y0, x1, _ = xy
        callout = (x0 + 92, y0 + 20, min(x0 + 780, x1 - 620), y0 + 66)
        if callout[2] <= callout[0] + 180:
            callout = (x0 + 92, y0 + 20, x1 - 250, y0 + 66)
        draw.rounded_rectangle((callout[0] + 3, callout[1] + 4, callout[2] + 3, callout[3] + 4), radius=14, fill=(204, 216, 228))
        draw.rounded_rectangle(callout, radius=13, fill=(255, 255, 255), outline=color, width=2)
        draw.ellipse((callout[0] + 10, callout[1] + 8, callout[0] + 46, callout[3] - 8), fill=color, outline=(255, 255, 255), width=2)
        center_text((callout[0] + 10, callout[1] + 8, callout[0] + 46, callout[3] - 8), num, _font(11, bold=True), (255, 255, 255))
        draw.text((callout[0] + 58, callout[1] + 7), title, fill=academic["title"], font=_font(13, bold=True))
        draw.text((callout[0] + 58, callout[1] + 27), _short_label(subtitle, 58), fill=academic["muted"], font=_font(7, bold=True))

    # A cleaner result ribbon across panel B gives the main performance claim the
    # same long-range presence as the ranking table.
    b_ribbon = (panel_b[0] + 742, panel_b[1] + 126, panel_b[2] - 78, panel_b[1] + 202)
    draw.rounded_rectangle((b_ribbon[0] + 5, b_ribbon[1] + 6, b_ribbon[2] + 5, b_ribbon[3] + 6), radius=18, fill=(204, 216, 227))
    draw.rounded_rectangle(b_ribbon, radius=17, fill=(255, 246, 224), outline=palette["amber"], width=3)
    center_text((b_ribbon[0] + 16, b_ribbon[1] + 6, b_ribbon[0] + 246, b_ribbon[3] - 6), f"{fold:.1f}x", _font(36, bold=True), palette["red"])
    draw.text((b_ribbon[0] + 266, b_ribbon[1] + 17), "lower raw JSD burden than the next best method", fill=academic["title"], font=_font(19, bold=True))
    draw.text((b_ribbon[0] + 268, b_ribbon[1] + 48), "all methods scored on the same Xenium-supervised spots", fill=academic["muted"], font=_font(10, bold=True))

    # Reference-style recomposition pass for the two panels that carry the
    # figure's first-glance story. Instead of adding more small annotations, this
    # pass repaints the interiors as large academic workflow/result plates.
    rng_comp = np.random.default_rng(313)

    def draw_comp_metric(xy: tuple[int, int, int, int], value: str, label: str, color: tuple[int, int, int], size: int = 20) -> None:
        x0, y0, x1, y1 = xy
        draw.rounded_rectangle((x0 + 3, y0 + 4, x1 + 3, y1 + 4), radius=13, fill=(207, 218, 229))
        draw.rounded_rectangle(xy, radius=12, fill=(255, 255, 255), outline=color, width=2)
        draw.rounded_rectangle((x0 + 10, y0 + 10, x0 + 24, y1 - 10), radius=5, fill=color)
        draw.text((x0 + 38, y0 + 7), value, fill=color, font=_font(size, bold=True))
        draw.text((x0 + 38, y0 + 34), label, fill=academic["title"], font=_font(8, bold=True))

    # Panel A, repainted as one uncluttered benchmark framework.
    a_plate2 = (panel_a[0] + 34, panel_a[1] + 104, panel_a[2] - 34, panel_a[3] - 34)
    draw.rounded_rectangle((a_plate2[0] + 7, a_plate2[1] + 8, a_plate2[2] + 7, a_plate2[3] + 8), radius=24, fill=(202, 214, 226))
    draw.rounded_rectangle(a_plate2, radius=23, fill=(253, 254, 255), outline=(162, 182, 198), width=2)
    a_title = (a_plate2[0] + 22, a_plate2[1] + 18, a_plate2[2] - 22, a_plate2[1] + 92)
    draw.rounded_rectangle(a_title, radius=17, fill=(239, 247, 249), outline=palette["teal"], width=2)
    draw.rounded_rectangle((a_title[0] + 16, a_title[1] + 12, a_title[0] + 260, a_title[3] - 12), radius=12, fill=palette["teal"], outline=(255, 255, 255), width=2)
    center_text((a_title[0] + 16, a_title[1] + 12, a_title[0] + 260, a_title[3] - 12), "BENCHMARK CONTRACT", _font(13, bold=True), (255, 255, 255))
