    bdraw = ImageDraw.Draw(bg)
    for y in range(height):
        t = y / max(height - 1, 1)
        bdraw.line((0, y, width, y), fill=(*_blend((253, 254, 255), (236, 244, 249), t), 255))
    for idx in range(54):
        y = 270 + idx * 38
        bdraw.line((50, y, width - 50, y + int(np.sin(idx * 0.7) * 16)), fill=(50, 128, 148, 22 if idx % 4 == 0 else 11), width=2)
    for idx in range(24):
        x = 110 + idx * 152
        bdraw.line((x, 230, x + 120, height - 120), fill=(190, 92, 120, 12), width=2)
    image.alpha_composite(bg)

    baseline = _load_csv(tables_dir / "table_3_baseline_comparison.csv")
