                {"method": "BayesPrism", "jsd": 0.2377, "spotwise_cosine": 0.7112, "mean_celltype_pearson": 0.0276, "rmse": 0.1191, "paired_permutation_p": 0.0001, "jsd_std": 0.0071},
                {"method": "RCTD (multi)", "jsd": 0.2443, "spotwise_cosine": 0.7146, "mean_celltype_pearson": -0.0216, "rmse": 0.1464, "paired_permutation_p": 0.0001, "jsd_std": 0.0112},
                {"method": "CARD", "jsd": 0.2726, "spotwise_cosine": 0.6755, "mean_celltype_pearson": -0.0110, "rmse": 0.1291, "paired_permutation_p": 0.0001, "jsd_std": 0.0097},
