    ax0, ay0, ax1, ay1 = panel_a
    league = (ax0 + 44, ay0 + 112, ax0 + 2180, ay1 - 128)
    draw.rounded_rectangle((league[0] + 7, league[1] + 8, league[2] + 7, league[3] + 8), radius=22, fill=(198, 209, 220))
    draw.rounded_rectangle(league, radius=21, fill=palette["ink"], outline=palette["red"], width=3)
    draw.text((league[0] + 28, league[1] + 22), "ranked raw JSD on 485 supervised spots", fill=(255, 255, 255), font=_font(24, bold=True))
    draw.text((league[0] + 30, league[1] + 58), "lower is better; horizontal distance is raw Jensen-Shannon divergence", fill=(199, 218, 228), font=_font(14, bold=True))
    rank = baseline.head(13).copy().reset_index(drop=True)
    jsd_values = rank["jsd"].to_numpy(dtype=float)
    max_jsd = max(float(np.nanmax(jsd_values)), best_jsd + 1e-6)
    plot_x0, plot_y0 = league[0] + 500, league[1] + 118
    plot_x1, plot_y1 = league[2] - 134, league[3] - 70
    for frac in np.linspace(0, 1, 6):
        x = int(plot_x0 + frac * (plot_x1 - plot_x0))
        draw.line((x, plot_y0 - 12, x, plot_y1 + 10), fill=(46, 62, 82), width=2 if frac in {0, 1} else 1)
        draw.text((x - 20, plot_y1 + 24), f"{frac * max_jsd:.2f}", fill=(164, 179, 196), font=_font(11, bold=True))
    best_x = int(plot_x0 + (best_jsd / max_jsd) * (plot_x1 - plot_x0))
    next_x = int(plot_x0 + (next_jsd / max_jsd) * (plot_x1 - plot_x0))
    band = Image.new("RGBA", image.size, (0, 0, 0, 0))
