    band_draw.rounded_rectangle((best_x + 8, plot_y0 - 10, max(next_x - 8, best_x + 80), plot_y1 + 10), radius=16, fill=(*palette["orange"], 32))
    band_draw.line((best_x, plot_y0 - 18, best_x, plot_y1 + 18), fill=(*palette["teal"], 230), width=5)
    band_draw.line((next_x, plot_y0 - 18, next_x, plot_y1 + 18), fill=(*palette["orange"], 230), width=5)
    image.alpha_composite(band)
    gap_box = (plot_x0 + 70, league[1] + 84, plot_x0 + 612, league[1] + 148)
    draw.rounded_rectangle((gap_box[0] + 4, gap_box[1] + 5, gap_box[2] + 4, gap_box[3] + 5), radius=17, fill=(8, 21, 35))
