        draw.line((plot_x0, y, x, y), fill=_blend(color, (255, 255, 255), 0.14 if is_model else 0.36), width=8 if is_model else 5)
        err = as_float(row.get("jsd_std"), np.nan)
        if np.isfinite(err) and err > 0:
            ex0 = int(plot_x0 + max(jsd - err, 0.0) / max_jsd * (plot_x1 - plot_x0))
            ex1 = int(plot_x0 + min(jsd + err, max_jsd) / max_jsd * (plot_x1 - plot_x0))
