    draw.text((verdict[0] + 26, verdict[1] + 58), f"{fold:.1f}x lower JSD than next best", fill=(255, 229, 238), font=_font(37, bold=True))
    draw.text((verdict[0] + 28, verdict[1] + 112), f"absolute gap {abs_gap:.3f}; paired tests significant versus all baselines", fill=(210, 230, 238), font=_font(14, bold=True))
