    header_y = matrix[1]
    for midx, (_, label, _) in enumerate(metrics):
        x = matrix[0] + method_w + midx * cell_w
        draw.rounded_rectangle((x + 4, header_y, x + cell_w - 6, header_y + 34), radius=8, fill=(235, 241, 246), outline=(215, 224, 234), width=1)
        center_text((x + 4, header_y, x + cell_w - 6, header_y + 34), label, _font(11, bold=True), palette["ink"])
    row_h2 = (matrix[3] - matrix[1] - 46) // max(len(rank), 1)
