def _write_figure1_quality_audit(
    source_path: Path,
    publication_exports: list[dict[str, Any]],
) -> dict[str, Any]:
    if not source_path.exists():
        return {"status": "fail", "reason": "Figure 1 source missing"}
    image = Image.open(source_path).convert("RGB")
    export_labels = {str(record.get("label")) for record in publication_exports}
    preview_records = [record for record in publication_exports if "preview" in str(record.get("label", ""))]
    audit = {
        "figure": "Figure 1",
        "source_path": str(source_path),
        "width": image.width,
        "height": image.height,
        "aspect_ratio": round(image.width / max(image.height, 1), 4),
        "pixel_std_sum": float(sum(ImageStat.Stat(image).stddev)),
        "required_exports": {
            "600dpi_tiff": "600dpi_tiff" in export_labels,
            "600dpi_pdf": "600dpi_pdf" in export_labels,
            "editor_preview_900px": "editor_preview_900px" in export_labels,
            "print_preview_1800px": "print_preview_1800px" in export_labels,
            "editor_first_view_1800px": "editor_first_view_1800px" in export_labels,
            "editor_first_view_900px": "editor_first_view_900px" in export_labels,
        },
        "preview_pixel_std_min": min((float(record.get("pixel_std_sum", 0.0)) for record in preview_records), default=0.0),
    }
    audit["status"] = (
        "pass"
        if audit["width"] >= 3000
        and audit["height"] >= 3000
        and audit["pixel_std_sum"] >= 50
        and audit["preview_pixel_std_min"] >= 50
        and all(audit["required_exports"].values())
        else "fail"
    )
    audit_path = source_path.with_name(f"{source_path.stem}_quality_audit.json")
    audit["path"] = str(audit_path)
    audit_path.write_text(json.dumps(audit, indent=2), encoding="utf-8")
    return audit


def build_manuscript_figures(
    output_dir: str | Path = DEFAULT_OUTPUT_DIR,
    run_dir: str | Path = DEFAULT_RUN_DIR,
    tables_dir: str | Path = DEFAULT_TABLES_DIR,
    external_pathology_dir: str | Path = DEFAULT_EXTERNAL_PATHOLOGY_DIR,
) -> dict[str, Any]:
    output_dir = Path(output_dir)
    run_dir = Path(run_dir)
    tables_dir = Path(tables_dir)
    pathology_dir = Path(external_pathology_dir)
    nature_dir = run_dir / "nature_analysis"
    prop_dir = nature_dir / "proportion_maps"
    output_dir.mkdir(parents=True, exist_ok=True)

    figure_paths = {
        "Figure 1": output_dir / "figure_1_workflow_schematic.png",
        "Figure 2": output_dir / "figure_2_spatial_cell_composition.png",
        "Figure 3": output_dir / "figure_3_baseline_performance.png",
        "Figure 4": output_dir / "figure_4_reliability_calibration.png",
        "Figure 5": output_dir / "figure_5_boundary_niche_pathology.png",
        "Supplementary Figure S1": output_dir / "supplementary_figure_s1_robustness.png",
    }
    editorial_paths = {
        "Editorial Graphical Abstract": output_dir / "figure_1_editorial_graphical_abstract.png",
        "Editor First-Glance Contact Sheet": output_dir / "editor_first_glance_contact_sheet.png",
    }

    _write_overview_schematic(figure_paths["Figure 1"], run_dir=run_dir, tables_dir=tables_dir)
    _write_editorial_graphical_abstract(editorial_paths["Editorial Graphical Abstract"], run_dir=run_dir, tables_dir=tables_dir)
    publication_exports = _save_publication_exports(figure_paths["Figure 1"])
    editorial_exports = _save_editorial_exports(editorial_paths["Editorial Graphical Abstract"])
    figure1_quality_audit = _write_figure1_quality_audit(figure_paths["Figure 1"], publication_exports)
    _write_spatial_composition_figure(figure_paths["Figure 2"], run_dir=run_dir)
    baseline = pd.read_csv(tables_dir / "table_3_baseline_comparison.csv")
    _write_benchmark_performance_showcase_figure(figure_paths["Figure 3"], tables_dir=tables_dir, run_dir=run_dir)
    _write_reliability_calibration_figure(figure_paths["Figure 4"], run_dir=run_dir)
    _write_boundary_niche_pathology_figure(figure_paths["Figure 5"], run_dir=run_dir, external_pathology_dir=pathology_dir)
    _write_robustness_supplement_figure(figure_paths["Supplementary Figure S1"], tables_dir=tables_dir, run_dir=run_dir)
    _write_editor_first_glance_contact_sheet(
        editorial_paths["Editor First-Glance Contact Sheet"],
        figure_paths,
        editorial_paths["Editorial Graphical Abstract"],
    )

    claims = {
        "Figure 1": "Reproducible benchmark and reference-aware multimodal method overview.",
        "Figure 2": "Spatial-omics atlas plate shows H&E-backed TME compartments, probability fields and compact cell-state grammar.",
        "Figure 3": "Comprehensive benchmark assessment wall shows matched-Xenium rank 1, multi-metric dominance, Rep1 adaptation, ablations and leakage-resistant controls.",
        "Figure 4": "Reliability-state atlas links localized H&E support, uncertainty risk states, calibration and niche-level gate subgroups.",
        "Figure 5": "High-contrast mechanism plate links H&E boundary preservation, biological niche identity and external pathology agreement.",
        "Supplementary Figure S1": "Robustness to realistic perturbations and input stress tests.",
    }
    rows = [_image_record(path, figure, path.stem, claims[figure]) for figure, path in figure_paths.items()]
    editorial_claims = {
        "Editorial Graphical Abstract": "High-impact 16:9 graphical abstract for editorial first-view and cover-slide use.",
        "Editor First-Glance Contact Sheet": "Thumbnail-scale visual hierarchy audit for the submission figure package.",
    }
    editorial_rows = [
        _image_record(
            path,
            asset,
            path.stem,
            editorial_claims.get(asset, "Editorial visual audit asset."),
        )
        for asset, path in editorial_paths.items()
    ]
    frame = pd.DataFrame(rows)
    manifest_csv = output_dir / "figure_manifest.csv"
    frame.to_csv(manifest_csv, index=False)
    manifest = {
        "generated_at_utc": datetime.now(timezone.utc).isoformat(),
        "output_dir": str(output_dir),
        "num_figures": len(rows),
        "num_pass": int((frame["status"] == "pass").sum()),
        "num_fail": int((frame["status"] != "pass").sum()),
        "figure_manifest_csv": str(manifest_csv),
        "figures": rows,
        "editorial_assets": editorial_rows,
        "publication_exports": publication_exports,
        "editorial_exports": editorial_exports,
        "figure1_quality_audit": figure1_quality_audit,
    }
    manifest_json = output_dir / "figure_manifest.json"
    manifest_json.write_text(json.dumps(manifest, indent=2), encoding="utf-8")
    lines = [
        "# WaveST-Gate Manuscript Figure Assets",
        "",
        f"Generated UTC: {manifest['generated_at_utc']}",
        "",
        "| Figure | Status | File | Size | Claim |",
        "| --- | --- | --- | --- | --- |",
    ]
    for row in rows:
        lines.append(f"| {row['figure']} | `{row['status']}` | `{row['path']}` | {row['width']}x{row['height']} | {row['claim']} |")
    if editorial_rows:
        lines.extend(["", "## Editorial Assets", "", "| Asset | Status | File | Size | Claim |", "| --- | --- | --- | --- | --- |"])
        for row in editorial_rows:
            lines.append(f"| {row['figure']} | `{row['status']}` | `{row['path']}` | {row['width']}x{row['height']} | {row['claim']} |")
    if publication_exports:
        lines.extend(["", "## Publication Exports", "", "| Label | File | Size |", "| --- | --- | --- |"])
        for export in publication_exports:
            lines.append(f"| {export['label']} | `{export['path']}` | {export['width']}x{export['height']} |")
    if editorial_exports:
        lines.extend(["", "## Editorial Exports", "", "| Label | File | Size |", "| --- | --- | --- |"])
        for export in editorial_exports:
            lines.append(f"| {export['label']} | `{export['path']}` | {export['width']}x{export['height']} |")
    if figure1_quality_audit:
        lines.extend(
            [
                "",
                "## Figure 1 Quality Audit",
                "",
                f"Status: `{figure1_quality_audit.get('status', 'unknown')}`",
                f"Audit file: `{figure1_quality_audit.get('path', '')}`",
            ]
        )
    manifest_md = output_dir / "figure_manifest.md"
    manifest_md.write_text("\n".join(lines), encoding="utf-8")
    manifest["figure_manifest_md"] = str(manifest_md)
    manifest_json.write_text(json.dumps(manifest, indent=2), encoding="utf-8")
    return manifest


def build_arg_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(description="Generate and validate WaveST-Gate manuscript figure assets.")
    parser.add_argument("--output-dir", default=str(DEFAULT_OUTPUT_DIR))
    parser.add_argument("--run-dir", default=str(DEFAULT_RUN_DIR))
    parser.add_argument("--tables-dir", default=str(DEFAULT_TABLES_DIR))
    parser.add_argument("--external-pathology-dir", default=str(DEFAULT_EXTERNAL_PATHOLOGY_DIR))
    return parser


def main(argv: list[str] | None = None) -> None:
    args = build_arg_parser().parse_args(argv)
    manifest = build_manuscript_figures(
        output_dir=args.output_dir,
        run_dir=args.run_dir,
        tables_dir=args.tables_dir,
        external_pathology_dir=args.external_pathology_dir,
    )
    print(json.dumps(manifest, indent=2), flush=True)


if __name__ == "__main__":
    main()
